export const techItmgrProfessionalQuestions: Question[] = [
  { id: 'tech-itmgr-prof-1', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'technology-strategy', type: 'multiple-choice', content: { es: 'La junta directiva le pide justificar una inversión de USD 2 millones en modernización de infraestructura cloud. El sistema actual on-premise funciona pero tiene costos operativos crecientes y limita la velocidad de innovación. ¿Cómo presenta el business case?', en: 'The board asks you to justify a USD 2 million investment in cloud infrastructure modernization. The current on-premise system works but has increasing operational costs and limits innovation speed. How do you present the business case?', fr: 'Le conseil d\'administration vous demande de justifier un investissement de 2 millions USD dans la modernisation de l\'infrastructure cloud. Le système on-premise actuel fonctionne mais a des coûts opérationnels croissants. Comment présentez-vous le business case ?' }, options: [{ id: 'a', text: { es: 'Presentar TCO comparativo a 5 años, ROI proyectado con métricas de time-to-market, análisis de riesgos de mantener el sistema actual, plan de migración por fases con quick wins identificados y benchmarks de la industria', en: 'Present 5-year comparative TCO, projected ROI with time-to-market metrics, risk analysis of maintaining the current system, phased migration plan with identified quick wins, and industry benchmarks', fr: 'Présenter le TCO comparatif sur 5 ans, le ROI projeté avec des métriques de time-to-market, l\'analyse des risques du système actuel, un plan de migration par phases avec des quick wins et des benchmarks de l\'industrie' }, value: 100 }, { id: 'b', text: { es: 'Enfocarse en las características técnicas de la nube y las tendencias del mercado', en: 'Focus on the cloud\'s technical features and market trends', fr: 'Se concentrer sur les caractéristiques techniques du cloud et les tendances du marché' }, value: 30 }, { id: 'c', text: { es: 'Comparar solo los costos mensuales de servidores actuales vs. cloud', en: 'Compare only the monthly costs of current servers vs. cloud', fr: 'Comparer uniquement les coûts mensuels des serveurs actuels vs. cloud' }, value: 25 }, { id: 'd', text: { es: 'Esperar a que la competencia migre primero y usar su experiencia como referencia', en: 'Wait for competitors to migrate first and use their experience as reference', fr: 'Attendre que la concurrence migre d\'abord et utiliser leur expérience comme référence' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-itmgr-prof-2', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'it-governance', type: 'multiple-choice', content: { es: 'Una auditoría interna revela que el 40% de las aplicaciones de la empresa usan frameworks con vulnerabilidades conocidas, no hay inventario actualizado de activos de software y las políticas de parcheo se aplican de forma inconsistente. ¿Cuál es su plan de acción?', en: 'An internal audit reveals that 40% of the company\'s applications use frameworks with known vulnerabilities, there is no updated software asset inventory, and patching policies are inconsistently applied. What is your action plan?', fr: 'Un audit interne révèle que 40% des applications de l\'entreprise utilisent des frameworks avec des vulnérabilités connues, il n\'y a pas d\'inventaire à jour des actifs logiciels et les politiques de patch sont appliquées de manière incohérente. Quel est votre plan d\'action ?' }, options: [{ id: 'a', text: { es: 'Implementar un CMDB automatizado, establecer SLAs de parcheo por criticidad, integrar escaneo de vulnerabilidades en el CI/CD, crear un comité de gobernanza de tecnología y establecer dashboards de cumplimiento', en: 'Implement an automated CMDB, establish patching SLAs by criticality, integrate vulnerability scanning into CI/CD, create a technology governance committee, and establish compliance dashboards', fr: 'Implémenter un CMDB automatisé, établir des SLAs de patchage par criticité, intégrer le scan de vulnérabilités dans le CI/CD, créer un comité de gouvernance technologique et établir des tableaux de bord de conformité' }, value: 100 }, { id: 'b', text: { es: 'Contratar a una consultora externa para resolver el problema de vulnerabilidades', en: 'Hire an external consultancy to solve the vulnerability problem', fr: 'Engager un cabinet de conseil externe pour résoudre le problème de vulnérabilités' }, value: 35 }, { id: 'c', text: { es: 'Priorizar la actualización inmediata de las aplicaciones más críticas', en: 'Prioritize immediate updating of the most critical applications', fr: 'Prioriser la mise à jour immédiate des applications les plus critiques' }, value: 55 }, { id: 'd', text: { es: 'Crear una política escrita de parcheo y esperar que los equipos la sigan', en: 'Create a written patching policy and expect teams to follow it', fr: 'Créer une politique écrite de patchage et s\'attendre à ce que les équipes la suivent' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-itmgr-prof-3', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'budget-vendor-mgmt', type: 'multiple-choice', content: { es: 'El principal proveedor de software ERP anuncia un aumento de licencias del 30% y un cambio de modelo on-premise a suscripción obligatoria cloud en 18 meses. El ERP es crítico para las operaciones. ¿Cómo gestiona esta situación?', en: 'The main ERP software vendor announces a 30% license increase and a mandatory shift from on-premise to cloud subscription in 18 months. The ERP is critical for operations. How do you manage this situation?', fr: 'Le principal fournisseur d\'ERP annonce une augmentation de 30% des licences et un passage obligatoire de l\'on-premise à l\'abonnement cloud en 18 mois. L\'ERP est critique pour les opérations. Comment gérez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Evaluar alternativas competitivas (negociación informada), negociar condiciones de transición, analizar TCO a 5 años de todas las opciones, crear un plan de contingencia y explorar soluciones open source como complemento', en: 'Evaluate competitive alternatives (informed negotiation), negotiate transition terms, analyze 5-year TCO of all options, create a contingency plan, and explore open source solutions as complement', fr: 'Évaluer les alternatives compétitives (négociation informée), négocier les conditions de transition, analyser le TCO sur 5 ans de toutes les options, créer un plan de contingence et explorer les solutions open source' }, value: 100 }, { id: 'b', text: { es: 'Aceptar las nuevas condiciones para mantener la continuidad operativa', en: 'Accept the new conditions to maintain operational continuity', fr: 'Accepter les nouvelles conditions pour maintenir la continuité opérationnelle' }, value: 20 }, { id: 'c', text: { es: 'Iniciar inmediatamente la migración a un ERP open source', en: 'Immediately start migration to an open source ERP', fr: 'Commencer immédiatement la migration vers un ERP open source' }, value: 30 }, { id: 'd', text: { es: 'Negociar solo el precio y aceptar el cambio a cloud', en: 'Negotiate only the price and accept the cloud change', fr: 'Négocier uniquement le prix et accepter le passage au cloud' }, value: 45 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-itmgr-prof-4', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'infrastructure-architecture', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene diseñando arquitecturas empresariales multi-cloud, incluyendo estrategias de disaster recovery, seguridad perimetral y cumplimiento regulatorio?', en: 'What level of experience do you have designing multi-cloud enterprise architectures, including disaster recovery strategies, perimeter security, and regulatory compliance?', fr: 'Quel niveau d\'expérience avez-vous dans la conception d\'architectures d\'entreprise multi-cloud, incluant les stratégies de reprise après sinistre, la sécurité périmétrique et la conformité réglementaire ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Experiencia limitada en arquitectura cloud empresarial', en: 'Limited experience in enterprise cloud architecture', fr: 'Expérience limitée en architecture cloud d\'entreprise' }, max: { es: 'Amplia experiencia liderando arquitecturas multi-cloud a gran escala', en: 'Extensive experience leading large-scale multi-cloud architectures', fr: 'Vaste expérience dans la direction d\'architectures multi-cloud à grande échelle' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-itmgr-prof-5', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'technology-strategy', type: 'scenario', content: { es: 'Usted es CTO de una empresa mediana (500 empleados) en el sector financiero. El CEO le pide presentar una estrategia tecnológica a 3 años que permita a la empresa competir con fintechs ágiles. Actualmente el 70% del presupuesto de TI se destina a mantener sistemas legacy.\nContexto: La empresa tiene 12 aplicaciones legacy en COBOL/Java, 3 desarrolladores que conocen el código legacy, un equipo total de TI de 25 personas y un presupuesto de TI de USD 3 millones anuales.', en: 'You are CTO of a mid-size company (500 employees) in the financial sector. The CEO asks you to present a 3-year technology strategy to compete with agile fintechs. Currently 70% of the IT budget goes to maintaining legacy systems.\nContext: The company has 12 legacy applications in COBOL/Java, 3 developers who know the legacy code, a total IT team of 25 people, and an annual IT budget of USD 3 million.', fr: 'Vous êtes CTO d\'une entreprise de taille moyenne (500 employés) dans le secteur financier. Le CEO vous demande de présenter une stratégie technologique à 3 ans pour concurrencer les fintechs agiles. Actuellement 70% du budget IT va à la maintenance des systèmes legacy.\nContexte : L\'entreprise a 12 applications legacy en COBOL/Java, 3 développeurs qui connaissent le code legacy, une équipe IT de 25 personnes et un budget IT de 3 millions USD annuels.' }, rubric: { es: 'Evaluar: (1) Estrategia de modernización gradual de legacy, (2) Plan de talento y capacitación, (3) Roadmap tecnológico con priorización de valor de negocio, (4) Estrategia de APIs para habilitar innovación, (5) Gestión del presupuesto (shift de mantenimiento a innovación), (6) KPIs de transformación digital.', en: 'Evaluate: (1) Gradual legacy modernization strategy, (2) Talent and training plan, (3) Technology roadmap with business value prioritization, (4) API strategy to enable innovation, (5) Budget management (shift from maintenance to innovation), (6) Digital transformation KPIs.', fr: 'Évaluer : (1) Stratégie de modernisation graduelle du legacy, (2) Plan de talent et formation, (3) Roadmap technologique avec priorisation de valeur business, (4) Stratégie d\'APIs pour l\'innovation, (5) Gestion budgétaire, (6) KPIs de transformation digitale.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-itmgr-prof-6', profileId: 'it-manager', categoryId: 'tech-itmgr-professional', competencyId: 'budget-vendor-mgmt', type: 'open-text', content: { es: 'Describa su proceso para evaluar y seleccionar proveedores de tecnología para un proyecto crítico. Incluya los criterios de evaluación, proceso de negociación y estrategia de gestión de riesgos de proveedores.', en: 'Describe your process for evaluating and selecting technology vendors for a critical project. Include the evaluation criteria, negotiation process, and vendor risk management strategy.', fr: 'Décrivez votre processus pour évaluer et sélectionner des fournisseurs de technologie pour un projet critique. Incluez les critères d\'évaluation, le processus de négociation et la stratégie de gestion des risques fournisseurs.' }, rubric: { es: 'Evaluar: (1) Criterios de evaluación estructurados (técnicos, financieros, estratégicos), (2) Proceso de RFP/RFI, (3) Evaluación de viabilidad a largo plazo del proveedor, (4) Estrategia de negociación, (5) Cláusulas contractuales de protección, (6) Plan de contingencia ante falla del proveedor.', en: 'Evaluate: (1) Structured evaluation criteria (technical, financial, strategic), (2) RFP/RFI process, (3) Long-term vendor viability assessment, (4) Negotiation strategy, (5) Protective contract clauses, (6) Contingency plan for vendor failure.', fr: 'Évaluer : (1) Critères d\'évaluation structurés, (2) Processus RFP/RFI, (3) Évaluation de la viabilité à long terme du fournisseur, (4) Stratégie de négociation, (5) Clauses contractuelles de protection, (6) Plan de contingence.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techItmgrSoftSkillsQuestions: Question[] = [
  { id: 'tech-itmgr-ss-1', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'tech-leadership', type: 'multiple-choice', content: { es: 'Tres de sus mejores desarrolladores amenazan con renunciar porque están frustrados con la burocracia, la falta de desafíos técnicos y la imposibilidad de dedicar tiempo a innovación. El mercado de talento es altamente competitivo. ¿Cómo aborda esta situación?', en: 'Three of your best developers threaten to resign because they are frustrated with bureaucracy, lack of technical challenges, and inability to dedicate time to innovation. The talent market is highly competitive. How do you address this situation?', fr: 'Trois de vos meilleurs développeurs menacent de démissionner à cause de la bureaucratie, du manque de défis techniques et de l\'impossibilité de consacrer du temps à l\'innovation. Le marché des talents est très compétitif. Comment abordez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Reunirse individualmente para entender motivaciones, implementar 20% time para proyectos de innovación, crear un career ladder técnico, reducir reuniones innecesarias y empoderar al equipo con autonomía en decisiones técnicas', en: 'Meet individually to understand motivations, implement 20% time for innovation projects, create a technical career ladder, reduce unnecessary meetings, and empower the team with autonomy in technical decisions', fr: 'Rencontrer individuellement pour comprendre les motivations, implémenter 20% de temps pour l\'innovation, créer un parcours de carrière technique, réduire les réunions inutiles et responsabiliser l\'équipe' }, value: 100 }, { id: 'b', text: { es: 'Ofrecer aumentos salariales inmediatos para retenerlos', en: 'Offer immediate salary increases to retain them', fr: 'Offrir des augmentations salariales immédiates pour les retenir' }, value: 35 }, { id: 'c', text: { es: 'Aceptar que es parte del ciclo natural y comenzar a buscar reemplazos', en: 'Accept that it is part of the natural cycle and start looking for replacements', fr: 'Accepter que cela fait partie du cycle naturel et commencer à chercher des remplaçants' }, value: 15 }, { id: 'd', text: { es: 'Escalar el problema a Recursos Humanos para que implementen un plan de retención', en: 'Escalate the issue to Human Resources to implement a retention plan', fr: 'Escalader le problème aux Ressources Humaines pour qu\'ils implémentent un plan de rétention' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-itmgr-ss-2', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'stakeholder-management', type: 'multiple-choice', content: { es: 'El director de marketing exige que su equipo de TI priorice la integración de una nueva plataforma de automatización de marketing, pero el director de operaciones necesita urgentemente una mejora en el sistema ERP. Ambos reportan al CEO y cada uno afirma que su proyecto es más crítico. ¿Cómo maneja esta situación?', en: 'The marketing director demands that your IT team prioritize integration of a new marketing automation platform, but the operations director urgently needs an ERP system improvement. Both report to the CEO and each claims their project is more critical. How do you handle this situation?', fr: 'Le directeur marketing exige que votre équipe IT priorise l\'intégration d\'une nouvelle plateforme d\'automatisation marketing, mais le directeur des opérations a un besoin urgent d\'amélioration du système ERP. Les deux reportent au CEO. Comment gérez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Establecer un framework de priorización transparente basado en impacto de negocio, urgencia y esfuerzo, presentar ambas opciones al comité directivo con datos y recomendación, y proponer un plan que equilibre entregas incrementales para ambos', en: 'Establish a transparent prioritization framework based on business impact, urgency, and effort, present both options to the steering committee with data and recommendation, and propose a plan that balances incremental deliveries for both', fr: 'Établir un cadre de priorisation transparent basé sur l\'impact business, l\'urgence et l\'effort, présenter les deux options au comité de direction avec données et recommandation, et proposer un plan équilibrant des livraisons incrémentales pour les deux' }, value: 100 }, { id: 'b', text: { es: 'Priorizar el proyecto que genere más ingresos a corto plazo', en: 'Prioritize the project that generates more short-term revenue', fr: 'Prioriser le projet qui génère plus de revenus à court terme' }, value: 45 }, { id: 'c', text: { es: 'Dejar que el CEO decida cuál proyecto va primero', en: 'Let the CEO decide which project goes first', fr: 'Laisser le CEO décider quel projet passe en premier' }, value: 30 }, { id: 'd', text: { es: 'Dividir el equipo en dos y hacer ambos proyectos simultáneamente', en: 'Split the team in two and do both projects simultaneously', fr: 'Diviser l\'équipe en deux et faire les deux projets simultanément' }, value: 25 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-itmgr-ss-3', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'tech-leadership', type: 'scale', content: { es: '¿Qué tan efectivo es creando y comunicando una visión tecnológica inspiradora que alinee a equipos técnicos y no técnicos hacia objetivos comunes?', en: 'How effective are you at creating and communicating an inspiring technology vision that aligns technical and non-technical teams toward common goals?', fr: 'Quelle est votre efficacité à créer et communiquer une vision technologique inspirante qui aligne les équipes techniques et non techniques vers des objectifs communs ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Me enfoco más en la ejecución técnica que en la visión estratégica', en: 'I focus more on technical execution than strategic vision', fr: 'Je me concentre plus sur l\'exécution technique que sur la vision stratégique' }, max: { es: 'Regularmente inspiro a equipos con una visión tecnológica clara y motivadora', en: 'I regularly inspire teams with a clear and motivating technology vision', fr: 'J\'inspire régulièrement les équipes avec une vision technologique claire et motivante' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-itmgr-ss-4', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'change-management', type: 'scale', content: { es: '¿Qué tan experimentado es gestionando la resistencia al cambio durante transformaciones digitales importantes (nuevos sistemas, procesos o formas de trabajo)?', en: 'How experienced are you at managing resistance to change during major digital transformations (new systems, processes, or ways of working)?', fr: 'Quelle est votre expérience dans la gestion de la résistance au changement lors de transformations numériques importantes (nouveaux systèmes, processus ou méthodes de travail) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Limitada experiencia gestionando resistencia organizacional al cambio', en: 'Limited experience managing organizational resistance to change', fr: 'Expérience limitée dans la gestion de la résistance organisationnelle au changement' }, max: { es: 'Amplia experiencia liderando transformaciones complejas con alto impacto humano', en: 'Extensive experience leading complex transformations with high human impact', fr: 'Vaste expérience dans la conduite de transformations complexes à fort impact humain' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-itmgr-ss-5', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'stakeholder-management', type: 'ranking', content: { es: 'Ordene las siguientes habilidades según su importancia para un CTO al comunicarse con la junta directiva:', en: 'Rank the following skills by importance for a CTO when communicating with the board of directors:', fr: 'Classez les compétences suivantes par importance pour un CTO lors de la communication avec le conseil d\'administration :' }, options: [{ id: 'a', text: { es: 'Traducir conceptos técnicos en impacto de negocio cuantificable', en: 'Translate technical concepts into quantifiable business impact', fr: 'Traduire les concepts techniques en impact business quantifiable' }, value: 1 }, { id: 'b', text: { es: 'Presentar riesgos tecnológicos con probabilidades e impacto financiero', en: 'Present technology risks with probabilities and financial impact', fr: 'Présenter les risques technologiques avec probabilités et impact financier' }, value: 2 }, { id: 'c', text: { es: 'Demostrar ROI de las inversiones tecnológicas', en: 'Demonstrate ROI of technology investments', fr: 'Démontrer le ROI des investissements technologiques' }, value: 3 }, { id: 'd', text: { es: 'Explicar detalles de la arquitectura y stack tecnológico', en: 'Explain architecture details and technology stack', fr: 'Expliquer les détails de l\'architecture et du stack technologique' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'tech-itmgr-ss-6', profileId: 'it-manager', categoryId: 'tech-itmgr-soft-skills', competencyId: 'change-management', type: 'open-text', content: { es: 'Describa cómo lideró o lideraría la implementación de una transformación digital significativa (nuevo ERP, migración a cloud, adopción de metodologías ágiles). ¿Qué estrategias de gestión del cambio aplicaría para asegurar la adopción exitosa?', en: 'Describe how you led or would lead the implementation of a significant digital transformation (new ERP, cloud migration, agile methodology adoption). What change management strategies would you apply to ensure successful adoption?', fr: 'Décrivez comment vous avez dirigé ou dirigeriez l\'implémentation d\'une transformation numérique significative. Quelles stratégies de gestion du changement appliqueriez-vous pour assurer l\'adoption réussie ?' }, rubric: { es: 'Evaluar: (1) Visión clara y comunicación del porqué, (2) Sponsors ejecutivos y coalition de cambio, (3) Plan de capacitación y soporte, (4) Gestión de expectativas y quick wins, (5) Métricas de adopción, (6) Feedback loops y ajustes iterativos.', en: 'Evaluate: (1) Clear vision and communication of why, (2) Executive sponsors and change coalition, (3) Training and support plan, (4) Expectation management and quick wins, (5) Adoption metrics, (6) Feedback loops and iterative adjustments.', fr: 'Évaluer : (1) Vision claire et communication du pourquoi, (2) Sponsors exécutifs et coalition de changement, (3) Plan de formation et support, (4) Gestion des attentes et quick wins, (5) Métriques d\'adoption, (6) Boucles de feedback et ajustements itératifs.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techItmgrReadinessQuestions: Question[] = [
  { id: 'tech-itmgr-rd-1', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'digital-transformation', type: 'multiple-choice', content: { es: 'Un competidor acaba de lanzar una plataforma completamente digital que amenaza con capturar el 20% de su mercado en 12 meses. Su empresa todavía depende de procesos manuales para el 60% de las operaciones. ¿Cuál es su respuesta estratégica?', en: 'A competitor has just launched a fully digital platform that threatens to capture 20% of your market in 12 months. Your company still relies on manual processes for 60% of operations. What is your strategic response?', fr: 'Un concurrent vient de lancer une plateforme entièrement numérique qui menace de capturer 20% de votre marché en 12 mois. Votre entreprise dépend encore de processus manuels pour 60% des opérations. Quelle est votre réponse stratégique ?' }, options: [{ id: 'a', text: { es: 'Crear un programa de transformación digital acelerada: identificar procesos de mayor impacto para automatizar primero, lanzar un producto digital mínimo viable en 90 días, establecer un equipo de innovación dedicado y medir ROI semanalmente', en: 'Create an accelerated digital transformation program: identify highest-impact processes to automate first, launch a minimum viable digital product in 90 days, establish a dedicated innovation team, and measure ROI weekly', fr: 'Créer un programme de transformation numérique accéléré : identifier les processus à plus fort impact à automatiser en premier, lancer un produit numérique minimum viable en 90 jours, établir une équipe d\'innovation dédiée et mesurer le ROI hebdomadairement' }, value: 100 }, { id: 'b', text: { es: 'Contratar una consultora para hacer un diagnóstico de transformación digital de 6 meses', en: 'Hire a consultancy to do a 6-month digital transformation diagnostic', fr: 'Engager un cabinet de conseil pour un diagnostic de transformation numérique de 6 mois' }, value: 30 }, { id: 'c', text: { es: 'Adquirir o asociarse con una fintech para acceder rápidamente a capacidades digitales', en: 'Acquire or partner with a fintech to quickly access digital capabilities', fr: 'Acquérir ou s\'associer avec une fintech pour accéder rapidement aux capacités numériques' }, value: 65 }, { id: 'd', text: { es: 'Enfocarse en fortalecer la propuesta de valor actual con mejor servicio al cliente presencial', en: 'Focus on strengthening the current value proposition with better in-person customer service', fr: 'Se concentrer sur le renforcement de la proposition de valeur actuelle avec un meilleur service client en personne' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-itmgr-rd-2', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'ai-ml-enterprise', type: 'multiple-choice', content: { es: 'La dirección quiere implementar IA en toda la organización pero no hay data scientists en el equipo, los datos están en silos y no hay una estrategia de datos definida. ¿Cómo construye las bases para la adopción de IA empresarial?', en: 'Management wants to implement AI across the organization but there are no data scientists on the team, data is siloed, and there is no defined data strategy. How do you build the foundation for enterprise AI adoption?', fr: 'La direction veut implémenter l\'IA dans toute l\'organisation mais il n\'y a pas de data scientists, les données sont en silos et il n\'y a pas de stratégie de données définie. Comment construisez-vous les bases pour l\'adoption de l\'IA d\'entreprise ?' }, options: [{ id: 'a', text: { es: 'Primero unificar datos con un data lakehouse, contratar un data engineer senior para liderar la estrategia de datos, implementar casos de uso de IA de bajo riesgo con herramientas no-code para generar quick wins y construir capacidades gradualmente', en: 'First unify data with a data lakehouse, hire a senior data engineer to lead the data strategy, implement low-risk AI use cases with no-code tools to generate quick wins, and build capabilities gradually', fr: 'D\'abord unifier les données avec un data lakehouse, embaucher un data engineer senior pour diriger la stratégie de données, implémenter des cas d\'usage IA à faible risque avec des outils no-code et construire les capacités graduellement' }, value: 100 }, { id: 'b', text: { es: 'Contratar inmediatamente un equipo de 5 data scientists y comprar una plataforma de IA enterprise', en: 'Immediately hire a team of 5 data scientists and buy an enterprise AI platform', fr: 'Embaucher immédiatement une équipe de 5 data scientists et acheter une plateforme d\'IA d\'entreprise' }, value: 30 }, { id: 'c', text: { es: 'Esperar a que la tecnología de IA sea más madura y fácil de implementar', en: 'Wait for AI technology to become more mature and easier to implement', fr: 'Attendre que la technologie d\'IA soit plus mature et plus facile à implémenter' }, value: 10 }, { id: 'd', text: { es: 'Externalizar completamente la capacidad de IA con un proveedor cloud', en: 'Completely outsource AI capability with a cloud provider', fr: 'Externaliser complètement la capacité d\'IA avec un fournisseur cloud' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-itmgr-rd-3', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'digital-transformation', type: 'scale', content: { es: '¿Qué tan preparado está para liderar la convergencia de tecnologías emergentes (IA, IoT, blockchain, edge computing) en soluciones empresariales integradas?', en: 'How prepared are you to lead the convergence of emerging technologies (AI, IoT, blockchain, edge computing) into integrated enterprise solutions?', fr: 'Dans quelle mesure êtes-vous prêt à diriger la convergence des technologies émergentes (IA, IoT, blockchain, edge computing) dans des solutions d\'entreprise intégrées ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco estas tecnologías a nivel conceptual', en: 'I know these technologies at a conceptual level', fr: 'Je connais ces technologies au niveau conceptuel' }, max: { es: 'He liderado la implementación exitosa de múltiples tecnologías emergentes integradas', en: 'I have led the successful implementation of multiple integrated emerging technologies', fr: 'J\'ai dirigé l\'implémentation réussie de multiples technologies émergentes intégrées' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-itmgr-rd-4', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'zero-trust-security', type: 'scale', content: { es: '¿Qué tan avanzada es su experiencia implementando modelos de seguridad zero-trust en organizaciones con trabajo híbrido, múltiples clouds y dispositivos BYOD?', en: 'How advanced is your experience implementing zero-trust security models in organizations with hybrid work, multiple clouds, and BYOD devices?', fr: 'Quelle est votre expérience dans l\'implémentation de modèles de sécurité zero-trust dans des organisations avec travail hybride, multiples clouds et appareils BYOD ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco los conceptos pero no he implementado zero-trust', en: 'I know the concepts but have not implemented zero-trust', fr: 'Je connais les concepts mais je n\'ai pas implémenté le zero-trust' }, max: { es: 'He liderado la transición completa a un modelo zero-trust', en: 'I have led a complete transition to a zero-trust model', fr: 'J\'ai dirigé la transition complète vers un modèle zero-trust' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-itmgr-rd-5', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'ai-ml-enterprise', type: 'scenario', content: { es: 'El CEO le presenta un caso: un proveedor de IA ofrece una solución que promete automatizar el 50% del servicio al cliente con un chatbot de IA generativa. El costo es USD 500K anuales y el proveedor garantiza un ROI de 300% en el primer año.\nContexto: La empresa recibe 100,000 consultas mensuales, el 70% son preguntas frecuentes. El equipo de servicio al cliente tiene 50 personas. La empresa no tiene experiencia previa con IA.', en: 'The CEO presents a case: an AI vendor offers a solution that promises to automate 50% of customer service with a generative AI chatbot. The cost is USD 500K annually and the vendor guarantees 300% ROI in the first year.\nContext: The company receives 100,000 monthly inquiries, 70% are FAQs. The customer service team has 50 people. The company has no prior AI experience.', fr: 'Le CEO présente un cas : un fournisseur d\'IA offre une solution qui promet d\'automatiser 50% du service client avec un chatbot d\'IA générative. Le coût est de 500K USD annuels et le fournisseur garantit un ROI de 300% la première année.\nContexte : L\'entreprise reçoit 100 000 demandes mensuelles, 70% sont des FAQ. L\'équipe de service client compte 50 personnes.' }, rubric: { es: 'Evaluar: (1) Análisis crítico de las promesas del proveedor, (2) Piloto controlado antes de despliegue completo, (3) Impacto en los empleados y plan de reskilling, (4) Métricas de éxito realistas, (5) Riesgos de reputación y calidad, (6) Alternativas y estrategia de build vs. buy.', en: 'Evaluate: (1) Critical analysis of vendor promises, (2) Controlled pilot before full deployment, (3) Employee impact and reskilling plan, (4) Realistic success metrics, (5) Reputation and quality risks, (6) Alternatives and build vs. buy strategy.', fr: 'Évaluer : (1) Analyse critique des promesses du fournisseur, (2) Pilote contrôlé avant déploiement complet, (3) Impact sur les employés et plan de reskilling, (4) Métriques de succès réalistes, (5) Risques de réputation et qualité, (6) Alternatives et stratégie build vs. buy.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-itmgr-rd-6', profileId: 'it-manager', categoryId: 'tech-itmgr-readiness', competencyId: 'zero-trust-security', type: 'open-text', content: { es: 'Describa su enfoque para diseñar e implementar una estrategia de seguridad zero-trust en una organización que actualmente depende de seguridad perimetral tradicional (firewall + VPN). Incluya la hoja de ruta, los desafíos principales y cómo mediría el éxito.', en: 'Describe your approach to designing and implementing a zero-trust security strategy in an organization that currently relies on traditional perimeter security (firewall + VPN). Include the roadmap, main challenges, and how you would measure success.', fr: 'Décrivez votre approche pour concevoir et implémenter une stratégie de sécurité zero-trust dans une organisation qui dépend actuellement de la sécurité périmétrique traditionnelle (firewall + VPN). Incluez la feuille de route, les défis principaux et comment vous mesureriez le succès.' }, rubric: { es: 'Evaluar: (1) Comprensión de los pilares de zero-trust, (2) Roadmap de implementación por fases, (3) Identidad y acceso como nuevo perímetro, (4) Microsegmentación de red, (5) Monitoreo continuo y análisis de comportamiento, (6) Impacto en la experiencia del usuario y productividad.', en: 'Evaluate: (1) Understanding of zero-trust pillars, (2) Phased implementation roadmap, (3) Identity and access as new perimeter, (4) Network microsegmentation, (5) Continuous monitoring and behavior analytics, (6) User experience and productivity impact.', fr: 'Évaluer : (1) Compréhension des piliers du zero-trust, (2) Roadmap d\'implémentation par phases, (3) Identité et accès comme nouveau périmètre, (4) Microsegmentation réseau, (5) Surveillance continue et analytique comportementale, (6) Impact sur l\'expérience utilisateur et la productivité.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

