export const techDataProfessionalQuestions: Question[] = [
  { id: 'tech-data-prof-1', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'statistical-analysis', type: 'multiple-choice', content: { es: 'Está analizando los resultados de un test A/B para una nueva funcionalidad del producto. El grupo de tratamiento muestra un aumento del 3% en la conversión con un p-value de 0.04. Sin embargo, el tamaño del efecto (Cohen\'s d) es 0.1 y el intervalo de confianza del 95% va de 0.1% a 5.9%. ¿Cuál es su interpretación y recomendación?', en: 'You are analyzing A/B test results for a new product feature. The treatment group shows a 3% conversion increase with a p-value of 0.04. However, the effect size (Cohen\'s d) is 0.1 and the 95% confidence interval ranges from 0.1% to 5.9%. What is your interpretation and recommendation?', fr: 'Vous analysez les résultats d\'un test A/B pour une nouvelle fonctionnalité produit. Le groupe de traitement montre une augmentation de 3% de la conversion avec un p-value de 0,04. Cependant, la taille d\'effet (Cohen\'s d) est 0,1 et l\'intervalle de confiance de 95% va de 0,1% à 5,9%. Quelle est votre interprétation et recommandation ?' }, options: [{ id: 'a', text: { es: 'El resultado es estadísticamente significativo pero con un efecto prácticamente pequeño y un IC amplio. Recomendar extender el test para reducir incertidumbre, segmentar por cohortes para identificar si el efecto es mayor en subgrupos, y calcular si el lift del 3% justifica el costo de implementación', en: 'The result is statistically significant but with a practically small effect and wide CI. Recommend extending the test to reduce uncertainty, segmenting by cohorts to identify if the effect is larger in subgroups, and calculating if the 3% lift justifies implementation cost', fr: 'Le résultat est statistiquement significatif mais avec un effet pratiquement faible et un IC large. Recommander d\'étendre le test, de segmenter par cohortes et de calculer si le lift de 3% justifie le coût d\'implémentation' }, value: 100 }, { id: 'b', text: { es: 'El p-value es menor a 0.05, por lo tanto la funcionalidad es efectiva y debe lanzarse', en: 'The p-value is less than 0.05, therefore the feature is effective and should be launched', fr: 'Le p-value est inférieur à 0,05, donc la fonctionnalité est efficace et doit être lancée' }, value: 25 }, { id: 'c', text: { es: 'El efecto es demasiado pequeño, se debe descartar la funcionalidad', en: 'The effect is too small, the feature should be discarded', fr: 'L\'effet est trop faible, la fonctionnalité doit être écartée' }, value: 35 }, { id: 'd', text: { es: 'Los resultados no son concluyentes, repetir el test exactamente igual', en: 'Results are inconclusive, repeat the test exactly the same way', fr: 'Les résultats ne sont pas concluants, répéter le test exactement de la même manière' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-data-prof-2', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'data-programming', type: 'multiple-choice', content: { es: 'Necesita procesar y analizar 500GB de datos de logs de usuario que se generan diariamente. Los datos están en formato JSON anidado con esquemas inconsistentes. Su equipo usa Python para análisis. ¿Cuál es su enfoque técnico?', en: 'You need to process and analyze 500GB of daily user log data. The data is in nested JSON format with inconsistent schemas. Your team uses Python for analysis. What is your technical approach?', fr: 'Vous devez traiter et analyser 500Go de logs utilisateur générés quotidiennement. Les données sont en format JSON imbriqué avec des schémas incohérents. Votre équipe utilise Python pour l\'analyse. Quelle est votre approche technique ?' }, options: [{ id: 'a', text: { es: 'Usar PySpark o Dask para procesamiento distribuido, definir un esquema con validación (Pydantic/Great Expectations), implementar un pipeline de ETL con Apache Airflow, almacenar en formato Parquet particionado y crear un data quality framework', en: 'Use PySpark or Dask for distributed processing, define a schema with validation (Pydantic/Great Expectations), implement an ETL pipeline with Apache Airflow, store in partitioned Parquet format, and create a data quality framework', fr: 'Utiliser PySpark ou Dask pour le traitement distribué, définir un schéma avec validation, implémenter un pipeline ETL avec Apache Airflow, stocker en format Parquet partitionné et créer un framework de qualité des données' }, value: 100 }, { id: 'b', text: { es: 'Usar pandas para cargar y procesar los datos en una máquina con mucha RAM', en: 'Use pandas to load and process the data on a machine with lots of RAM', fr: 'Utiliser pandas pour charger et traiter les données sur une machine avec beaucoup de RAM' }, value: 20 }, { id: 'c', text: { es: 'Cargar los datos directamente en una base de datos SQL y consultarlos desde ahí', en: 'Load the data directly into a SQL database and query from there', fr: 'Charger les données directement dans une base de données SQL et les interroger depuis là' }, value: 40 }, { id: 'd', text: { es: 'Pedir al equipo de ingeniería que construya un pipeline antes de que el equipo de datos pueda trabajar', en: 'Ask the engineering team to build a pipeline before the data team can work', fr: 'Demander à l\'équipe d\'ingénierie de construire un pipeline avant que l\'équipe data puisse travailler' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-data-prof-3', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'data-visualization', type: 'multiple-choice', content: { es: 'La dirección ejecutiva le pide un dashboard para monitorear la salud del negocio en tiempo real. Actualmente reciben 15 reportes semanales en PDF de diferentes departamentos, muchos con datos contradictorios. ¿Cómo diseña la solución?', en: 'The executive team asks you for a dashboard to monitor business health in real-time. They currently receive 15 weekly PDF reports from different departments, many with contradictory data. How do you design the solution?', fr: 'La direction exécutive vous demande un tableau de bord pour surveiller la santé de l\'entreprise en temps réel. Ils reçoivent actuellement 15 rapports PDF hebdomadaires de différents départements, beaucoup avec des données contradictoires. Comment concevez-vous la solution ?' }, options: [{ id: 'a', text: { es: 'Primero unificar las fuentes de datos con un modelo semántico único (single source of truth), definir KPIs con los stakeholders, diseñar un dashboard con drill-down por nivel jerárquico, implementar alertas automáticas y establecer gobernanza de datos', en: 'First unify data sources with a single semantic model (single source of truth), define KPIs with stakeholders, design a dashboard with drill-down by hierarchical level, implement automatic alerts, and establish data governance', fr: 'D\'abord unifier les sources de données avec un modèle sémantique unique, définir les KPIs avec les parties prenantes, concevoir un tableau de bord avec drill-down par niveau hiérarchique, implémenter des alertes automatiques et établir la gouvernance des données' }, value: 100 }, { id: 'b', text: { es: 'Crear un dashboard de Power BI que consolide todos los reportes PDF existentes', en: 'Create a Power BI dashboard that consolidates all existing PDF reports', fr: 'Créer un tableau de bord Power BI qui consolide tous les rapports PDF existants' }, value: 35 }, { id: 'c', text: { es: 'Automatizar la generación de los 15 reportes PDF con datos actualizados', en: 'Automate the generation of the 15 PDF reports with updated data', fr: 'Automatiser la génération des 15 rapports PDF avec des données à jour' }, value: 15 }, { id: 'd', text: { es: 'Implementar Tableau con conexiones directas a cada base de datos departamental', en: 'Implement Tableau with direct connections to each departmental database', fr: 'Implémenter Tableau avec des connexions directes à chaque base de données départementale' }, value: 45 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-data-prof-4', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'ml-modeling', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene construyendo modelos de machine learning completos (desde feature engineering hasta despliegue y monitoreo en producción)?', en: 'What level of experience do you have building complete machine learning models (from feature engineering through deployment and production monitoring)?', fr: 'Quel niveau d\'expérience avez-vous dans la construction de modèles de machine learning complets (du feature engineering au déploiement et surveillance en production) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'He entrenado modelos básicos en entornos de laboratorio (notebooks)', en: 'I have trained basic models in lab environments (notebooks)', fr: 'J\'ai entraîné des modèles basiques en environnement de laboratoire (notebooks)' }, max: { es: 'He desplegado y mantenido múltiples modelos en producción con MLOps completo', en: 'I have deployed and maintained multiple models in production with complete MLOps', fr: 'J\'ai déployé et maintenu plusieurs modèles en production avec MLOps complet' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-data-prof-5', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'statistical-analysis', type: 'scenario', content: { es: 'Una empresa de e-commerce le contrata para investigar por qué las ventas han caído un 15% en los últimos 3 meses a pesar de que el tráfico web ha aumentado un 10%. El equipo de marketing afirma que sus campañas son más efectivas que nunca, el equipo de producto dice que no ha habido cambios significativos.\nContexto: Tiene acceso a datos de Google Analytics, CRM, plataforma de pagos y encuestas NPS. El inventario de productos se ha mantenido estable.', en: 'An e-commerce company hires you to investigate why sales have dropped 15% in the last 3 months despite web traffic increasing by 10%. The marketing team claims their campaigns are more effective than ever, the product team says there have been no significant changes.\nContext: You have access to Google Analytics, CRM, payment platform, and NPS survey data. Product inventory has remained stable.', fr: 'Une entreprise e-commerce vous embauche pour investiguer pourquoi les ventes ont chuté de 15% ces 3 derniers mois malgré une augmentation du trafic web de 10%. L\'équipe marketing affirme que ses campagnes sont plus efficaces que jamais. L\'équipe produit dit qu\'il n\'y a pas eu de changements significatifs.\nContexte : Vous avez accès aux données de Google Analytics, CRM, plateforme de paiement et enquêtes NPS.' }, rubric: { es: 'Evaluar: (1) Metodología de análisis estructurada (hipótesis, datos, validación), (2) Análisis de funnel de conversión, (3) Segmentación de datos por canal, dispositivo y cohorte, (4) Correlación vs. causalidad, (5) Comunicación de hallazgos con recomendaciones accionables, (6) Plan de seguimiento y métricas de validación.', en: 'Evaluate: (1) Structured analysis methodology (hypothesis, data, validation), (2) Conversion funnel analysis, (3) Data segmentation by channel, device, and cohort, (4) Correlation vs. causation, (5) Communication of findings with actionable recommendations, (6) Follow-up plan and validation metrics.', fr: 'Évaluer : (1) Méthodologie d\'analyse structurée, (2) Analyse du funnel de conversion, (3) Segmentation des données par canal, appareil et cohorte, (4) Corrélation vs. causalité, (5) Communication des résultats avec recommandations actionnables, (6) Plan de suivi et métriques de validation.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-data-prof-6', profileId: 'data-analyst', categoryId: 'tech-data-professional', competencyId: 'ml-modeling', type: 'open-text', content: { es: 'Describa el proceso completo que seguiría para construir un modelo predictivo de churn (abandono de clientes). Incluya las fases desde la definición del problema hasta el monitoreo en producción.', en: 'Describe the complete process you would follow to build a customer churn prediction model. Include the phases from problem definition through production monitoring.', fr: 'Décrivez le processus complet que vous suivriez pour construire un modèle prédictif de churn (abandon de clients). Incluez les phases depuis la définition du problème jusqu\'à la surveillance en production.' }, rubric: { es: 'Evaluar: (1) Definición clara del problema y métrica objetivo, (2) Feature engineering y selección de variables, (3) Manejo de desbalanceo de clases, (4) Selección y comparación de modelos, (5) Validación cruzada y métricas de evaluación apropiadas, (6) Plan de despliegue, reentrenamiento y monitoreo de drift.', en: 'Evaluate: (1) Clear problem definition and target metric, (2) Feature engineering and variable selection, (3) Class imbalance handling, (4) Model selection and comparison, (5) Cross-validation and appropriate evaluation metrics, (6) Deployment, retraining, and drift monitoring plan.', fr: 'Évaluer : (1) Définition claire du problème et métrique cible, (2) Feature engineering et sélection de variables, (3) Gestion du déséquilibre de classes, (4) Sélection et comparaison de modèles, (5) Validation croisée et métriques d\'évaluation appropriées, (6) Plan de déploiement, réentraînement et surveillance du drift.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techDataSoftSkillsQuestions: Question[] = [
  { id: 'tech-data-ss-1', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'data-storytelling', type: 'multiple-choice', content: { es: 'Debe presentar al CEO los resultados de un análisis complejo que muestra que la estrategia de pricing actual está dejando USD 2 millones anuales en la mesa. El análisis involucra modelos de elasticidad de precio, segmentación de clientes y simulaciones Monte Carlo. El CEO tiene 15 minutos. ¿Cómo estructura su presentación?', en: 'You must present to the CEO the results of a complex analysis showing the current pricing strategy is leaving USD 2 million annually on the table. The analysis involves price elasticity models, customer segmentation, and Monte Carlo simulations. The CEO has 15 minutes. How do you structure your presentation?', fr: 'Vous devez présenter au CEO les résultats d\'une analyse complexe montrant que la stratégie de pricing actuelle laisse 2 millions USD par an sur la table. L\'analyse implique des modèles d\'élasticité-prix, segmentation de clients et simulations Monte Carlo. Le CEO a 15 minutes. Comment structurez-vous votre présentation ?' }, options: [{ id: 'a', text: { es: 'Empezar con el impacto financiero ($2M), mostrar 2-3 visualizaciones clave que cuenten la historia, presentar 3 escenarios de acción con ROI proyectado, dejar los detalles técnicos como apéndice, y terminar con una recomendación clara y próximos pasos', en: 'Start with the financial impact ($2M), show 2-3 key visualizations that tell the story, present 3 action scenarios with projected ROI, leave technical details as an appendix, and end with a clear recommendation and next steps', fr: 'Commencer par l\'impact financier (2M$), montrer 2-3 visualisations clés qui racontent l\'histoire, présenter 3 scénarios d\'action avec ROI projeté, laisser les détails techniques en annexe et terminer avec une recommandation claire' }, value: 100 }, { id: 'b', text: { es: 'Explicar la metodología paso a paso para que el CEO entienda la solidez del análisis', en: 'Explain the methodology step by step so the CEO understands the analysis rigor', fr: 'Expliquer la méthodologie étape par étape pour que le CEO comprenne la rigueur de l\'analyse' }, value: 20 }, { id: 'c', text: { es: 'Enviar el reporte completo por email y usar los 15 minutos para Q&A', en: 'Send the complete report by email and use the 15 minutes for Q&A', fr: 'Envoyer le rapport complet par email et utiliser les 15 minutes pour Q&A' }, value: 30 }, { id: 'd', text: { es: 'Mostrar todas las visualizaciones del análisis para demostrar la profundidad del trabajo', en: 'Show all the analysis visualizations to demonstrate the depth of work', fr: 'Montrer toutes les visualisations de l\'analyse pour démontrer la profondeur du travail' }, value: 15 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-data-ss-2', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'cross-functional-collab', type: 'multiple-choice', content: { es: 'El equipo de ventas le pide un reporte que muestre que su nueva estrategia aumentó los ingresos un 20%. Al analizar los datos, descubre que el aumento se debe en un 15% a estacionalidad y solo un 5% puede atribuirse a la nueva estrategia. ¿Cómo comunica esto?', en: 'The sales team asks you for a report showing their new strategy increased revenue by 20%. Upon analyzing the data, you discover that 15% of the increase is due to seasonality and only 5% can be attributed to the new strategy. How do you communicate this?', fr: 'L\'équipe commerciale vous demande un rapport montrant que leur nouvelle stratégie a augmenté les revenus de 20%. En analysant les données, vous découvrez que 15% de l\'augmentation est due à la saisonnalité et seulement 5% peut être attribué à la nouvelle stratégie. Comment communiquez-vous cela ?' }, options: [{ id: 'a', text: { es: 'Presentar los datos de manera transparente pero constructiva: reconocer el crecimiento total, explicar la descomposición con visualizaciones claras, destacar que el 5% atribuible a la estrategia sigue siendo positivo y sugerir formas de aumentar ese impacto', en: 'Present the data transparently but constructively: acknowledge total growth, explain the decomposition with clear visualizations, highlight that the 5% attributable to the strategy is still positive, and suggest ways to increase that impact', fr: 'Présenter les données de manière transparente mais constructive : reconnaître la croissance totale, expliquer la décomposition avec des visualisations claires, souligner que les 5% attribuables à la stratégie sont positifs et suggérer des moyens d\'augmenter cet impact' }, value: 100 }, { id: 'b', text: { es: 'Generar el reporte que el equipo de ventas pidió mostrando el 20% de aumento', en: 'Generate the report the sales team requested showing the 20% increase', fr: 'Générer le rapport que l\'équipe commerciale a demandé montrant l\'augmentation de 20%' }, value: 10 }, { id: 'c', text: { es: 'Enviar solo los datos crudos y dejar que el equipo de ventas saque sus propias conclusiones', en: 'Send only the raw data and let the sales team draw their own conclusions', fr: 'Envoyer uniquement les données brutes et laisser l\'équipe commerciale tirer ses propres conclusions' }, value: 20 }, { id: 'd', text: { es: 'Comunicar directamente al jefe de ventas que su estrategia solo generó un 5% de impacto', en: 'Communicate directly to the sales manager that their strategy only generated 5% impact', fr: 'Communiquer directement au directeur commercial que sa stratégie n\'a généré que 5% d\'impact' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-data-ss-3', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'data-storytelling', type: 'scale', content: { es: '¿Qué tan efectivo es adaptando la complejidad de sus presentaciones de datos según la audiencia (ejecutivos, técnicos, operativos)?', en: 'How effective are you at adapting the complexity of your data presentations based on the audience (executives, technical, operational)?', fr: 'Quelle est votre efficacité à adapter la complexité de vos présentations de données selon l\'audience (exécutifs, techniques, opérationnels) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Tiendo a usar el mismo nivel de detalle técnico para todas las audiencias', en: 'I tend to use the same level of technical detail for all audiences', fr: 'J\'ai tendance à utiliser le même niveau de détail technique pour toutes les audiences' }, max: { es: 'Adapto naturalmente el mensaje, el nivel de detalle y las visualizaciones a cada audiencia', en: 'I naturally adapt the message, detail level, and visualizations to each audience', fr: 'J\'adapte naturellement le message, le niveau de détail et les visualisations à chaque audience' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-data-ss-4', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'critical-thinking-data', type: 'scale', content: { es: '¿Con qué frecuencia cuestiona la calidad, el sesgo y las limitaciones de los datos antes de iniciar un análisis?', en: 'How often do you question data quality, bias, and limitations before starting an analysis?', fr: 'À quelle fréquence remettez-vous en question la qualité, le biais et les limites des données avant de commencer une analyse ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Generalmente confío en que los datos disponibles son correctos y completos', en: 'I generally trust that available data is correct and complete', fr: 'Je fais généralement confiance au fait que les données disponibles sont correctes et complètes' }, max: { es: 'Siempre cuestiono y valido los datos antes de cualquier análisis, documentando limitaciones', en: 'I always question and validate data before any analysis, documenting limitations', fr: 'Je remets toujours en question et valide les données avant toute analyse, en documentant les limites' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-data-ss-5', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'cross-functional-collab', type: 'ranking', content: { es: 'Ordene las siguientes habilidades según su importancia para un analista de datos al trabajar con equipos de negocio:', en: 'Rank the following skills by importance for a data analyst when working with business teams:', fr: 'Classez les compétences suivantes par importance pour un analyste de données travaillant avec des équipes métier :' }, options: [{ id: 'a', text: { es: 'Capacidad para traducir preguntas de negocio en preguntas de datos', en: 'Ability to translate business questions into data questions', fr: 'Capacité à traduire des questions métier en questions de données' }, value: 1 }, { id: 'b', text: { es: 'Habilidad para presentar insights de forma accionable', en: 'Ability to present insights in an actionable way', fr: 'Capacité à présenter des insights de manière actionnable' }, value: 2 }, { id: 'c', text: { es: 'Dominio de herramientas de visualización avanzadas', en: 'Mastery of advanced visualization tools', fr: 'Maîtrise des outils de visualisation avancés' }, value: 3 }, { id: 'd', text: { es: 'Conocimiento profundo de algoritmos de machine learning', en: 'Deep knowledge of machine learning algorithms', fr: 'Connaissance approfondie des algorithmes de machine learning' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'tech-data-ss-6', profileId: 'data-analyst', categoryId: 'tech-data-soft-skills', competencyId: 'critical-thinking-data', type: 'open-text', content: { es: 'Describa una situación donde los datos le llevaron a una conclusión inicial que resultó ser incorrecta o engañosa. ¿Qué señales de alarma ignoró inicialmente y qué cambió en su proceso analítico a raíz de esa experiencia?', en: 'Describe a situation where data led you to an initial conclusion that turned out to be incorrect or misleading. What warning signs did you initially ignore and what changed in your analytical process as a result of that experience?', fr: 'Décrivez une situation où les données vous ont mené à une conclusion initiale qui s\'est avérée incorrecte ou trompeuse. Quels signaux d\'alarme avez-vous initialement ignorés et qu\'avez-vous changé dans votre processus analytique suite à cette expérience ?' }, rubric: { es: 'Evaluar: (1) Reconocimiento honesto del error, (2) Identificación de sesgos (confirmación, sobrevivientes, etc.), (3) Problemas de calidad de datos no detectados, (4) Lecciones aprendidas concretas, (5) Cambios implementados en el proceso, (6) Madurez profesional y humildad intelectual.', en: 'Evaluate: (1) Honest recognition of error, (2) Identification of biases (confirmation, survivorship, etc.), (3) Undetected data quality issues, (4) Concrete lessons learned, (5) Changes implemented in the process, (6) Professional maturity and intellectual humility.', fr: 'Évaluer : (1) Reconnaissance honnête de l\'erreur, (2) Identification des biais, (3) Problèmes de qualité de données non détectés, (4) Leçons apprises concrètes, (5) Changements implémentés dans le processus, (6) Maturité professionnelle et humilité intellectuelle.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techDataReadinessQuestions: Question[] = [
  { id: 'tech-data-rd-1', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'generative-ai-data', type: 'multiple-choice', content: { es: 'Los modelos de lenguaje grande (LLMs) están transformando el análisis de datos. ¿Cómo integraría herramientas de IA generativa en su flujo de trabajo de análisis sin comprometer la rigurosidad analítica?', en: 'Large language models (LLMs) are transforming data analysis. How would you integrate generative AI tools into your analysis workflow without compromising analytical rigor?', fr: 'Les grands modèles de langage (LLMs) transforment l\'analyse de données. Comment intégreriez-vous des outils d\'IA générative dans votre flux de travail d\'analyse sans compromettre la rigueur analytique ?' }, options: [{ id: 'a', text: { es: 'Usar LLMs para exploración inicial de datos, generación de hipótesis y prototipado rápido de código, pero siempre validar los resultados con métodos estadísticos rigurosos y revisión humana, documentando las limitaciones', en: 'Use LLMs for initial data exploration, hypothesis generation, and rapid code prototyping, but always validate results with rigorous statistical methods and human review, documenting limitations', fr: 'Utiliser les LLMs pour l\'exploration initiale des données, la génération d\'hypothèses et le prototypage rapide de code, mais toujours valider les résultats avec des méthodes statistiques rigoureuses et une revue humaine' }, value: 100 }, { id: 'b', text: { es: 'Confiar en las respuestas de los LLMs para análisis de datos ya que son muy precisos', en: 'Trust LLM responses for data analysis since they are very accurate', fr: 'Faire confiance aux réponses des LLMs pour l\'analyse de données car ils sont très précis' }, value: 10 }, { id: 'c', text: { es: 'No usar LLMs para análisis de datos serios, solo para tareas administrativas', en: 'Do not use LLMs for serious data analysis, only for administrative tasks', fr: 'Ne pas utiliser les LLMs pour l\'analyse de données sérieuse, seulement pour les tâches administratives' }, value: 30 }, { id: 'd', text: { es: 'Usar LLMs solo para generar código Python y SQL, no para interpretación de resultados', en: 'Use LLMs only to generate Python and SQL code, not for result interpretation', fr: 'Utiliser les LLMs uniquement pour générer du code Python et SQL, pas pour l\'interprétation des résultats' }, value: 55 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-data-rd-2', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'real-time-analytics', type: 'multiple-choice', content: { es: 'Su empresa necesita pasar de reportes batch diarios a analítica en tiempo real para un sistema de detección de fraude. ¿Cuál es su enfoque para esta transición?', en: 'Your company needs to move from daily batch reports to real-time analytics for a fraud detection system. What is your approach to this transition?', fr: 'Votre entreprise doit passer de rapports batch quotidiens à l\'analytique en temps réel pour un système de détection de fraude. Quelle est votre approche pour cette transition ?' }, options: [{ id: 'a', text: { es: 'Implementar una arquitectura Lambda/Kappa con streaming (Kafka/Kinesis), modelos ML servidos en tiempo real, dashboards con latencia sub-segundo, mantener el batch como backup y migrar gradualmente los modelos de fraude', en: 'Implement a Lambda/Kappa architecture with streaming (Kafka/Kinesis), real-time served ML models, sub-second latency dashboards, keep batch as backup, and gradually migrate fraud models', fr: 'Implémenter une architecture Lambda/Kappa avec streaming (Kafka/Kinesis), modèles ML servis en temps réel, tableaux de bord avec latence sub-seconde, garder le batch comme backup et migrer graduellement les modèles de fraude' }, value: 100 }, { id: 'b', text: { es: 'Reducir la frecuencia del batch de diario a cada hora', en: 'Reduce batch frequency from daily to hourly', fr: 'Réduire la fréquence du batch de quotidien à horaire' }, value: 25 }, { id: 'c', text: { es: 'Comprar una plataforma de analítica en tiempo real llave en mano', en: 'Buy a turnkey real-time analytics platform', fr: 'Acheter une plateforme d\'analytique en temps réel clé en main' }, value: 40 }, { id: 'd', text: { es: 'Migrar todo de una vez al nuevo sistema de tiempo real', en: 'Migrate everything at once to the new real-time system', fr: 'Migrer tout d\'un coup vers le nouveau système en temps réel' }, value: 20 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-data-rd-3', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'generative-ai-data', type: 'scale', content: { es: '¿Qué tan preparado está para usar herramientas de IA generativa (ChatGPT, Claude, Copilot) como asistentes en su trabajo de análisis de datos?', en: 'How prepared are you to use generative AI tools (ChatGPT, Claude, Copilot) as assistants in your data analysis work?', fr: 'Dans quelle mesure êtes-vous prêt à utiliser des outils d\'IA générative (ChatGPT, Claude, Copilot) comme assistants dans votre travail d\'analyse de données ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'No he explorado estas herramientas para análisis de datos', en: 'I have not explored these tools for data analysis', fr: 'Je n\'ai pas exploré ces outils pour l\'analyse de données' }, max: { es: 'Las uso diariamente y he desarrollado prompts especializados para análisis', en: 'I use them daily and have developed specialized prompts for analysis', fr: 'Je les utilise quotidiennement et j\'ai développé des prompts spécialisés pour l\'analyse' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-data-rd-4', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'data-ethics', type: 'scale', content: { es: '¿Qué tan familiarizado está con marcos de ética de datos, regulaciones de privacidad (GDPR, CCPA) y técnicas de fairness en modelos de ML?', en: 'How familiar are you with data ethics frameworks, privacy regulations (GDPR, CCPA), and fairness techniques in ML models?', fr: 'Dans quelle mesure êtes-vous familier avec les cadres d\'éthique des données, les réglementations de confidentialité (RGPD, CCPA) et les techniques de fairness dans les modèles ML ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco los conceptos básicos pero no los he aplicado formalmente', en: 'I know the basics but have not formally applied them', fr: 'Je connais les concepts de base mais je ne les ai pas formellement appliqués' }, max: { es: 'He implementado frameworks de ética de datos y fairness en proyectos en producción', en: 'I have implemented data ethics and fairness frameworks in production projects', fr: 'J\'ai implémenté des frameworks d\'éthique des données et de fairness dans des projets en production' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-data-rd-5', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'real-time-analytics', type: 'scenario', content: { es: 'Una empresa de retail le pide diseñar un sistema de recomendaciones personalizado en tiempo real para su app móvil con 5 millones de usuarios activos diarios. El sistema debe considerar historial de compras, navegación actual, inventario en tienda cercana y tendencias estacionales.\nContexto: La empresa tiene datos en BigQuery (históricos) y eventos en tiempo real via Firebase. El equipo de datos tiene 3 personas. El presupuesto de infraestructura es USD 10K mensuales.', en: 'A retail company asks you to design a real-time personalized recommendation system for their mobile app with 5 million daily active users. The system must consider purchase history, current browsing, nearby store inventory, and seasonal trends.\nContext: The company has data in BigQuery (historical) and real-time events via Firebase. The data team has 3 people. The infrastructure budget is USD 10K monthly.', fr: 'Une entreprise de retail vous demande de concevoir un système de recommandations personnalisé en temps réel pour son app mobile avec 5 millions d\'utilisateurs actifs quotidiens. Le système doit considérer l\'historique d\'achats, la navigation actuelle, l\'inventaire en magasin proche et les tendances saisonnières.\nContexte : L\'entreprise a des données dans BigQuery et des événements en temps réel via Firebase. L\'équipe data a 3 personnes. Le budget infrastructure est de 10K USD mensuels.' }, rubric: { es: 'Evaluar: (1) Arquitectura de datos escalable y eficiente en costos, (2) Estrategia de features en tiempo real vs. batch, (3) Algoritmos de recomendación apropiados, (4) Plan de evaluación A/B, (5) Gestión de cold-start y edge cases, (6) Consideraciones de privacidad y consentimiento del usuario.', en: 'Evaluate: (1) Scalable and cost-efficient data architecture, (2) Real-time vs. batch feature strategy, (3) Appropriate recommendation algorithms, (4) A/B evaluation plan, (5) Cold-start and edge case management, (6) Privacy and user consent considerations.', fr: 'Évaluer : (1) Architecture de données scalable et efficiente en coûts, (2) Stratégie de features temps réel vs. batch, (3) Algorithmes de recommandation appropriés, (4) Plan d\'évaluation A/B, (5) Gestion du cold-start et cas limites, (6) Considérations de confidentialité et consentement utilisateur.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-data-rd-6', profileId: 'data-analyst', categoryId: 'tech-data-readiness', competencyId: 'data-ethics', type: 'open-text', content: { es: 'Describa cómo abordaría la detección y mitigación de sesgos en un modelo de ML utilizado para la aprobación de créditos. ¿Qué técnicas de fairness aplicaría y cómo equilibraría la precisión del modelo con la equidad?', en: 'Describe how you would approach bias detection and mitigation in an ML model used for credit approval. What fairness techniques would you apply and how would you balance model accuracy with equity?', fr: 'Décrivez comment vous aborderiez la détection et l\'atténuation des biais dans un modèle ML utilisé pour l\'approbation de crédits. Quelles techniques de fairness appliqueriez-vous et comment équilibreriez-vous la précision du modèle avec l\'équité ?' }, rubric: { es: 'Evaluar: (1) Comprensión de tipos de sesgo (histórico, de representación, de medición), (2) Métricas de fairness (disparate impact, equalized odds, etc.), (3) Técnicas de mitigación pre/in/post-processing, (4) Trade-offs entre precisión y fairness, (5) Auditoría y transparencia del modelo, (6) Marco regulatorio y legal aplicable.', en: 'Evaluate: (1) Understanding of bias types (historical, representation, measurement), (2) Fairness metrics (disparate impact, equalized odds, etc.), (3) Pre/in/post-processing mitigation techniques, (4) Accuracy-fairness trade-offs, (5) Model auditing and transparency, (6) Applicable regulatory and legal framework.', fr: 'Évaluer : (1) Compréhension des types de biais, (2) Métriques de fairness, (3) Techniques de mitigation pré/in/post-processing, (4) Compromis précision-fairness, (5) Audit et transparence du modèle, (6) Cadre réglementaire et légal applicable.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

