export const techCyberProfessionalQuestions: Question[] = [
  { id: 'tech-cyber-prof-1', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'network-security', type: 'multiple-choice', content: { es: 'Un análisis de tráfico revela conexiones salientes sospechosas desde 3 estaciones de trabajo hacia una IP externa en un país con alta actividad de cibercrimen. Las conexiones ocurren en horarios no laborales usando el puerto 443. El antivirus no ha detectado nada. ¿Cuál es su plan de acción inmediato?', en: 'A traffic analysis reveals suspicious outbound connections from 3 workstations to an external IP in a country with high cybercrime activity. Connections occur during non-business hours using port 443. The antivirus has detected nothing. What is your immediate action plan?', fr: 'Une analyse de trafic révèle des connexions sortantes suspectes depuis 3 postes de travail vers une IP externe dans un pays avec une forte activité cybercriminelle. Les connexions se produisent en dehors des heures de travail via le port 443. L\'antivirus n\'a rien détecté. Quel est votre plan d\'action immédiat ?' }, options: [{ id: 'a', text: { es: 'Aislar las estaciones de la red sin apagarlas, capturar memoria RAM y tráfico de red para análisis forense, bloquear la IP en el firewall, verificar IOCs en el SIEM, notificar al equipo de respuesta a incidentes y buscar movimiento lateral en la red', en: 'Isolate the workstations from the network without shutting them down, capture RAM and network traffic for forensic analysis, block the IP at the firewall, verify IOCs in the SIEM, notify the incident response team, and search for lateral movement in the network', fr: 'Isoler les postes du réseau sans les éteindre, capturer la mémoire RAM et le trafic réseau pour l\'analyse forensique, bloquer l\'IP au pare-feu, vérifier les IOCs dans le SIEM, notifier l\'équipe de réponse aux incidents et chercher le mouvement latéral dans le réseau' }, value: 100 }, { id: 'b', text: { es: 'Apagar inmediatamente las 3 estaciones de trabajo y formatearlas', en: 'Immediately shut down the 3 workstations and reformat them', fr: 'Éteindre immédiatement les 3 postes de travail et les reformater' }, value: 15 }, { id: 'c', text: { es: 'Actualizar el antivirus y ejecutar un escaneo completo en las máquinas afectadas', en: 'Update the antivirus and run a full scan on the affected machines', fr: 'Mettre à jour l\'antivirus et exécuter un scan complet sur les machines affectées' }, value: 25 }, { id: 'd', text: { es: 'Monitorear el tráfico durante unos días más para recopilar más evidencia antes de actuar', en: 'Monitor the traffic for a few more days to gather more evidence before acting', fr: 'Surveiller le trafic pendant quelques jours de plus pour rassembler plus de preuves avant d\'agir' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-cyber-prof-2', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'vulnerability-assessment', type: 'multiple-choice', content: { es: 'Un escaneo de vulnerabilidades revela 847 vulnerabilidades en su infraestructura: 12 críticas (CVSS 9+), 85 altas, 340 medias y 410 bajas. El equipo de seguridad tiene 4 personas y los equipos de desarrollo tienen resistencia a aplicar parches por miedo a romper funcionalidad. ¿Cómo prioriza y gestiona la remediación?', en: 'A vulnerability scan reveals 847 vulnerabilities in your infrastructure: 12 critical (CVSS 9+), 85 high, 340 medium, and 410 low. The security team has 4 people and development teams resist patching for fear of breaking functionality. How do you prioritize and manage remediation?', fr: 'Un scan de vulnérabilités révèle 847 vulnérabilités dans votre infrastructure : 12 critiques (CVSS 9+), 85 hautes, 340 moyennes et 410 basses. L\'équipe sécurité a 4 personnes et les équipes de développement résistent aux patchs par peur de casser la fonctionnalité. Comment priorisez-vous et gérez-vous la remédiation ?' }, options: [{ id: 'a', text: { es: 'Priorizar por riesgo real (CVSS + exploitabilidad + exposición + criticidad del activo), establecer SLAs de remediación escalonados, integrar escaneo en CI/CD para prevención, crear un proceso de patching con testing automatizado y reportar métricas de reducción de riesgo a la dirección', en: 'Prioritize by real risk (CVSS + exploitability + exposure + asset criticality), establish tiered remediation SLAs, integrate scanning into CI/CD for prevention, create a patching process with automated testing, and report risk reduction metrics to management', fr: 'Prioriser par risque réel (CVSS + exploitabilité + exposition + criticité de l\'actif), établir des SLAs de remédiation échelonnés, intégrer le scan dans le CI/CD, créer un processus de patchage avec tests automatisés et rapporter les métriques de réduction de risque à la direction' }, value: 100 }, { id: 'b', text: { es: 'Parchear las 12 vulnerabilidades críticas inmediatamente e ignorar el resto', en: 'Patch the 12 critical vulnerabilities immediately and ignore the rest', fr: 'Patcher les 12 vulnérabilités critiques immédiatement et ignorer le reste' }, value: 40 }, { id: 'c', text: { es: 'Generar tickets para cada vulnerabilidad y asignarlos a los equipos de desarrollo', en: 'Generate tickets for each vulnerability and assign them to development teams', fr: 'Générer des tickets pour chaque vulnérabilité et les assigner aux équipes de développement' }, value: 30 }, { id: 'd', text: { es: 'Implementar WAF y IPS como mitigación compensatoria mientras se planifica el parcheo', en: 'Implement WAF and IPS as compensating controls while planning patching', fr: 'Implémenter WAF et IPS comme contrôles compensatoires en attendant le patchage' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-cyber-prof-3', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'incident-response', type: 'multiple-choice', content: { es: 'A las 2 AM recibe una alerta: el sistema de monitoreo detecta encriptación masiva de archivos en un servidor de archivos compartidos. El ransomware se está propagando y ya ha afectado el 30% de los archivos. ¿Cuáles son sus primeros 30 minutos de respuesta?', en: 'At 2 AM you receive an alert: the monitoring system detects massive file encryption on a shared file server. Ransomware is spreading and has already affected 30% of files. What are your first 30 minutes of response?', fr: 'À 2h du matin, vous recevez une alerte : le système de surveillance détecte un chiffrement massif de fichiers sur un serveur de fichiers partagé. Le ransomware se propage et a déjà affecté 30% des fichiers. Quelles sont vos 30 premières minutes de réponse ?' }, options: [{ id: 'a', text: { es: 'Desconectar el servidor afectado de la red, activar el plan de respuesta a incidentes, verificar la integridad de los backups, identificar el vector de entrada y las cuentas comprometidas, aislar segmentos de red potencialmente afectados y notificar a la dirección y al equipo legal', en: 'Disconnect the affected server from the network, activate the incident response plan, verify backup integrity, identify the entry vector and compromised accounts, isolate potentially affected network segments, and notify management and legal team', fr: 'Déconnecter le serveur affecté du réseau, activer le plan de réponse aux incidents, vérifier l\'intégrité des sauvegardes, identifier le vecteur d\'entrée et les comptes compromis, isoler les segments réseau potentiellement affectés et notifier la direction et l\'équipe juridique' }, value: 100 }, { id: 'b', text: { es: 'Apagar el servidor inmediatamente para detener la encriptación', en: 'Shut down the server immediately to stop the encryption', fr: 'Éteindre le serveur immédiatement pour arrêter le chiffrement' }, value: 35 }, { id: 'c', text: { es: 'Intentar identificar el tipo de ransomware para buscar un descifrador disponible', en: 'Try to identify the ransomware type to look for an available decryptor', fr: 'Essayer d\'identifier le type de ransomware pour chercher un déchiffreur disponible' }, value: 25 }, { id: 'd', text: { es: 'Restaurar inmediatamente desde el backup más reciente', en: 'Immediately restore from the most recent backup', fr: 'Restaurer immédiatement depuis la sauvegarde la plus récente' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-cyber-prof-4', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'security-compliance', type: 'scale', content: { es: '¿Qué nivel de experiencia tiene implementando y manteniendo programas de cumplimiento de seguridad basados en frameworks como ISO 27001, NIST CSF o SOC 2?', en: 'What level of experience do you have implementing and maintaining security compliance programs based on frameworks such as ISO 27001, NIST CSF, or SOC 2?', fr: 'Quel niveau d\'expérience avez-vous dans l\'implémentation et la maintenance de programmes de conformité de sécurité basés sur des cadres comme ISO 27001, NIST CSF ou SOC 2 ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco los frameworks pero no he liderado su implementación', en: 'I know the frameworks but have not led their implementation', fr: 'Je connais les cadres mais je n\'ai pas dirigé leur implémentation' }, max: { es: 'He liderado la certificación completa de una organización en ISO 27001 o similar', en: 'I have led an organization\'s complete ISO 27001 or similar certification', fr: 'J\'ai dirigé la certification complète d\'une organisation en ISO 27001 ou similaire' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-cyber-prof-5', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'network-security', type: 'scenario', content: { es: 'Una auditoría de seguridad externa revela que la red de su organización tiene segmentación deficiente: la red de producción, desarrollo y oficinas comparte el mismo segmento. Un atacante que comprometa cualquier estación de trabajo tendría acceso potencial a los servidores de producción con datos de clientes.\nContexto: La organización tiene 200 empleados, 50 servidores (20 en producción), red plana con un solo firewall perimetral, y presupuesto limitado de USD 100K para mejoras de seguridad.', en: 'An external security audit reveals that your organization\'s network has poor segmentation: production, development, and office networks share the same segment. An attacker compromising any workstation would have potential access to production servers with customer data.\nContext: The organization has 200 employees, 50 servers (20 in production), a flat network with a single perimeter firewall, and a limited USD 100K security improvement budget.', fr: 'Un audit de sécurité externe révèle que le réseau de votre organisation a une segmentation déficiente : les réseaux de production, développement et bureaux partagent le même segment. Un attaquant compromettant n\'importe quel poste de travail aurait un accès potentiel aux serveurs de production avec des données clients.\nContexte : L\'organisation a 200 employés, 50 serveurs (20 en production), un réseau plat avec un seul pare-feu périmétrique et un budget limité de 100K USD.' }, rubric: { es: 'Evaluar: (1) Plan de microsegmentación priorizado por criticidad, (2) Implementación de VLANs y firewalls internos, (3) Control de acceso basado en roles (RBAC), (4) Monitoreo de tráfico entre segmentos, (5) Gestión del cambio y minimización de disrupciones, (6) Plan de implementación por fases dentro del presupuesto.', en: 'Evaluate: (1) Microsegmentation plan prioritized by criticality, (2) VLAN and internal firewall implementation, (3) Role-based access control (RBAC), (4) Inter-segment traffic monitoring, (5) Change management and disruption minimization, (6) Phased implementation plan within budget.', fr: 'Évaluer : (1) Plan de microsegmentation priorisé par criticité, (2) Implémentation de VLANs et pare-feu internes, (3) Contrôle d\'accès basé sur les rôles, (4) Surveillance du trafic inter-segments, (5) Gestion du changement et minimisation des disruptions, (6) Plan d\'implémentation par phases dans le budget.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-cyber-prof-6', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-professional', competencyId: 'vulnerability-assessment', type: 'open-text', content: { es: 'Describa cómo diseñaría e implementaría un programa de bug bounty o de pruebas de penetración continuas para una aplicación web con 1 millón de usuarios. Incluya el alcance, reglas de engagement, herramientas y proceso de remediación.', en: 'Describe how you would design and implement a bug bounty or continuous penetration testing program for a web application with 1 million users. Include the scope, rules of engagement, tools, and remediation process.', fr: 'Décrivez comment vous concevriez et implémenteriez un programme de bug bounty ou de tests de pénétration continus pour une application web avec 1 million d\'utilisateurs. Incluez le périmètre, les règles d\'engagement, les outils et le processus de remédiation.' }, rubric: { es: 'Evaluar: (1) Definición clara del alcance y reglas, (2) Estructura de recompensas y clasificación de severidad, (3) Proceso de triage y validación, (4) SLAs de remediación, (5) Herramientas y automatización, (6) Métricas de éxito del programa.', en: 'Evaluate: (1) Clear scope and rules definition, (2) Reward structure and severity classification, (3) Triage and validation process, (4) Remediation SLAs, (5) Tools and automation, (6) Program success metrics.', fr: 'Évaluer : (1) Définition claire du périmètre et des règles, (2) Structure de récompenses et classification de sévérité, (3) Processus de triage et validation, (4) SLAs de remédiation, (5) Outils et automatisation, (6) Métriques de succès du programme.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techCyberSoftSkillsQuestions: Question[] = [
  { id: 'tech-cyber-ss-1', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'risk-communication', type: 'multiple-choice', content: { es: 'Descubre una vulnerabilidad crítica en el sistema de pagos de la empresa que podría exponer datos de tarjetas de crédito de 50,000 clientes. La remediación requiere 2 semanas de trabajo y tomará offline el sistema de pagos durante 4 horas. El director financiero se opone a cualquier downtime. ¿Cómo comunica el riesgo?', en: 'You discover a critical vulnerability in the company\'s payment system that could expose credit card data of 50,000 customers. Remediation requires 2 weeks of work and will take the payment system offline for 4 hours. The CFO opposes any downtime. How do you communicate the risk?', fr: 'Vous découvrez une vulnérabilité critique dans le système de paiement qui pourrait exposer les données de cartes de crédit de 50 000 clients. La remédiation nécessite 2 semaines de travail et mettra le système hors ligne pendant 4 heures. Le directeur financier s\'oppose à tout temps d\'arrêt. Comment communiquez-vous le risque ?' }, options: [{ id: 'a', text: { es: 'Cuantificar el riesgo en términos financieros (multas PCI-DSS, costo de brecha, daño reputacional vs. costo de 4 horas de downtime), presentar escenarios de probabilidad, proponer un horario de mantenimiento de mínimo impacto y documentar formalmente el riesgo si se decide no actuar', en: 'Quantify the risk in financial terms (PCI-DSS fines, breach cost, reputational damage vs. cost of 4 hours downtime), present probability scenarios, propose a minimum-impact maintenance window, and formally document the risk if a decision is made not to act', fr: 'Quantifier le risque en termes financiers (amendes PCI-DSS, coût de brèche, dommage réputationnel vs. coût de 4 heures d\'indisponibilité), présenter des scénarios de probabilité, proposer une fenêtre de maintenance à impact minimum et documenter formellement le risque si on décide de ne pas agir' }, value: 100 }, { id: 'b', text: { es: 'Explicar los detalles técnicos de la vulnerabilidad al CFO para que entienda la gravedad', en: 'Explain the technical details of the vulnerability to the CFO so they understand the severity', fr: 'Expliquer les détails techniques de la vulnérabilité au CFO pour qu\'il comprenne la gravité' }, value: 25 }, { id: 'c', text: { es: 'Escalar directamente al CEO ya que el CFO no entiende los riesgos', en: 'Escalate directly to the CEO since the CFO does not understand the risks', fr: 'Escalader directement au CEO puisque le CFO ne comprend pas les risques' }, value: 35 }, { id: 'd', text: { es: 'Implementar controles compensatorios temporales y posponer la remediación', en: 'Implement temporary compensating controls and postpone remediation', fr: 'Implémenter des contrôles compensatoires temporaires et reporter la remédiation' }, value: 50 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-cyber-ss-2', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'security-awareness-training', type: 'multiple-choice', content: { es: 'El 60% de los empleados caen en simulaciones de phishing a pesar de haber completado el training anual obligatorio de seguridad. Los empleados se quejan de que el training es aburrido y no aplica a su trabajo diario. ¿Cómo rediseña el programa?', en: '60% of employees fall for phishing simulations despite completing the mandatory annual security training. Employees complain the training is boring and doesn\'t apply to their daily work. How do you redesign the program?', fr: '60% des employés tombent dans les simulations de phishing malgré la formation annuelle obligatoire. Les employés se plaignent que la formation est ennuyeuse et ne s\'applique pas à leur travail quotidien. Comment redessinez-vous le programme ?' }, options: [{ id: 'a', text: { es: 'Diseñar micro-aprendizajes mensuales personalizados por departamento, gamificar con competencias entre equipos, usar phishing simulado progresivo con feedback inmediato, reconocer públicamente a los que reportan amenazas y medir la reducción del click rate', en: 'Design monthly personalized micro-learning by department, gamify with team competitions, use progressive simulated phishing with immediate feedback, publicly recognize those who report threats, and measure click rate reduction', fr: 'Concevoir des micro-apprentissages mensuels personnalisés par département, gamifier avec des compétitions entre équipes, utiliser du phishing simulé progressif avec feedback immédiat, reconnaître publiquement ceux qui signalent les menaces et mesurer la réduction du taux de clics' }, value: 100 }, { id: 'b', text: { es: 'Hacer el training más largo y exhaustivo para cubrir todos los escenarios posibles', en: 'Make the training longer and more exhaustive to cover all possible scenarios', fr: 'Rendre la formation plus longue et exhaustive pour couvrir tous les scénarios possibles' }, value: 15 }, { id: 'c', text: { es: 'Implementar consecuencias disciplinarias para quienes caigan en phishing', en: 'Implement disciplinary consequences for those who fall for phishing', fr: 'Implémenter des conséquences disciplinaires pour ceux qui tombent dans le phishing' }, value: 20 }, { id: 'd', text: { es: 'Contratar una empresa especializada para que dé el training presencial', en: 'Hire a specialized company to deliver in-person training', fr: 'Engager une entreprise spécialisée pour donner la formation en présentiel' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-cyber-ss-3', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'risk-communication', type: 'scale', content: { es: '¿Qué tan efectivo es comunicando riesgos de ciberseguridad a la dirección ejecutiva usando lenguaje de negocio en lugar de jerga técnica?', en: 'How effective are you at communicating cybersecurity risks to executive management using business language instead of technical jargon?', fr: 'Quelle est votre efficacité à communiquer les risques de cybersécurité à la direction exécutive en utilisant le langage d\'affaires plutôt que le jargon technique ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Tiendo a usar terminología técnica que los ejecutivos no entienden', en: 'I tend to use technical terminology that executives do not understand', fr: 'J\'ai tendance à utiliser une terminologie technique que les exécutifs ne comprennent pas' }, max: { es: 'Puedo traducir cualquier riesgo técnico en impacto de negocio y costo financiero', en: 'I can translate any technical risk into business impact and financial cost', fr: 'Je peux traduire tout risque technique en impact business et coût financier' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-cyber-ss-4', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'pressure-management', type: 'scale', content: { es: '¿Cómo evalúa su capacidad para mantener la claridad mental y tomar decisiones acertadas durante un incidente de seguridad activo con impacto significativo en el negocio?', en: 'How do you evaluate your ability to maintain mental clarity and make sound decisions during an active security incident with significant business impact?', fr: 'Comment évaluez-vous votre capacité à maintenir la clarté mentale et à prendre des décisions pertinentes lors d\'un incident de sécurité actif avec un impact significatif sur l\'activité ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Los incidentes de alta presión afectan mi capacidad de decisión', en: 'High-pressure incidents affect my decision-making ability', fr: 'Les incidents sous haute pression affectent ma capacité de décision' }, max: { es: 'Mantengo la calma y sigo procedimientos estructurados incluso en los peores escenarios', en: 'I remain calm and follow structured procedures even in worst-case scenarios', fr: 'Je reste calme et suis des procédures structurées même dans les pires scénarios' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-cyber-ss-5', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'security-awareness-training', type: 'ranking', content: { es: 'Ordene las siguientes estrategias según su efectividad para reducir el riesgo humano en ciberseguridad:', en: 'Rank the following strategies by effectiveness for reducing human risk in cybersecurity:', fr: 'Classez les stratégies suivantes par efficacité pour réduire le risque humain en cybersécurité :' }, options: [{ id: 'a', text: { es: 'Simulaciones de phishing frecuentes con feedback educativo inmediato', en: 'Frequent phishing simulations with immediate educational feedback', fr: 'Simulations de phishing fréquentes avec feedback éducatif immédiat' }, value: 1 }, { id: 'b', text: { es: 'Cultura de reporte de incidentes sin penalización', en: 'Incident reporting culture without penalization', fr: 'Culture de signalement d\'incidents sans pénalisation' }, value: 2 }, { id: 'c', text: { es: 'Controles técnicos automatizados (MFA, filtros de email)', en: 'Automated technical controls (MFA, email filters)', fr: 'Contrôles techniques automatisés (MFA, filtres email)' }, value: 3 }, { id: 'd', text: { es: 'Training anual obligatorio con certificación', en: 'Mandatory annual training with certification', fr: 'Formation annuelle obligatoire avec certification' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'tech-cyber-ss-6', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-soft-skills', competencyId: 'pressure-management', type: 'open-text', content: { es: 'Describa su experiencia más desafiante respondiendo a un incidente de seguridad. ¿Cómo gestionó la presión, coordinó al equipo y comunicó con la dirección durante la crisis? ¿Qué mejoraría si pudiera volver a hacerlo?', en: 'Describe your most challenging experience responding to a security incident. How did you manage pressure, coordinate the team, and communicate with management during the crisis? What would you improve if you could do it over?', fr: 'Décrivez votre expérience la plus difficile de réponse à un incident de sécurité. Comment avez-vous géré la pression, coordonné l\'équipe et communiqué avec la direction pendant la crise ? Qu\'amélioreriez-vous si vous pouviez le refaire ?' }, rubric: { es: 'Evaluar: (1) Liderazgo bajo presión real, (2) Proceso de toma de decisiones, (3) Coordinación de equipo multifuncional, (4) Comunicación de crisis, (5) Lecciones aprendidas y mejoras implementadas, (6) Resiliencia personal y del equipo.', en: 'Evaluate: (1) Leadership under real pressure, (2) Decision-making process, (3) Cross-functional team coordination, (4) Crisis communication, (5) Lessons learned and improvements implemented, (6) Personal and team resilience.', fr: 'Évaluer : (1) Leadership sous pression réelle, (2) Processus de prise de décision, (3) Coordination d\'équipe interfonctionnelle, (4) Communication de crise, (5) Leçons apprises et améliorations implémentées, (6) Résilience personnelle et de l\'équipe.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techCyberReadinessQuestions: Question[] = [
  { id: 'tech-cyber-rd-1', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'ai-powered-threats', type: 'multiple-choice', content: { es: 'Los atacantes están usando IA generativa para crear emails de phishing altamente personalizados que evaden los filtros tradicionales, deepfakes de audio para ingeniería social y malware polimórfico que muta con cada ejecución. ¿Cómo adapta su estrategia de defensa?', en: 'Attackers are using generative AI to create highly personalized phishing emails that evade traditional filters, audio deepfakes for social engineering, and polymorphic malware that mutates with each execution. How do you adapt your defense strategy?', fr: 'Les attaquants utilisent l\'IA générative pour créer des emails de phishing hautement personnalisés qui évitent les filtres traditionnels, des deepfakes audio pour l\'ingénierie sociale et des malwares polymorphes qui mutent à chaque exécution. Comment adaptez-vous votre stratégie de défense ?' }, options: [{ id: 'a', text: { es: 'Implementar detección basada en IA/ML que analice comportamiento (no solo firmas), entrenar al equipo en reconocimiento de deepfakes, establecer verificación multi-canal para solicitudes sensibles, participar en comunidades de threat intelligence de IA y actualizar playbooks de respuesta', en: 'Implement AI/ML-based detection that analyzes behavior (not just signatures), train the team in deepfake recognition, establish multi-channel verification for sensitive requests, participate in AI threat intelligence communities, and update response playbooks', fr: 'Implémenter la détection basée sur l\'IA/ML qui analyse le comportement (pas seulement les signatures), former l\'équipe à la reconnaissance des deepfakes, établir la vérification multi-canal pour les demandes sensibles, participer aux communautés de threat intelligence IA et mettre à jour les playbooks de réponse' }, value: 100 }, { id: 'b', text: { es: 'Bloquear el uso de herramientas de IA en toda la organización', en: 'Block the use of AI tools across the entire organization', fr: 'Bloquer l\'utilisation d\'outils d\'IA dans toute l\'organisation' }, value: 10 }, { id: 'c', text: { es: 'Aumentar la frecuencia de simulaciones de phishing tradicionales', en: 'Increase the frequency of traditional phishing simulations', fr: 'Augmenter la fréquence des simulations de phishing traditionnelles' }, value: 30 }, { id: 'd', text: { es: 'Comprar una solución anti-IA de un proveedor especializado', en: 'Buy an anti-AI solution from a specialized vendor', fr: 'Acheter une solution anti-IA d\'un fournisseur spécialisé' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-cyber-rd-2', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'cloud-security-evolution', type: 'multiple-choice', content: { es: 'Su organización migra cargas de trabajo críticas a una arquitectura multi-cloud (AWS + Azure) con microservicios en Kubernetes. El modelo de seguridad perimetral tradicional ya no es efectivo. ¿Cómo redefine la estrategia de seguridad?', en: 'Your organization is migrating critical workloads to a multi-cloud architecture (AWS + Azure) with Kubernetes microservices. The traditional perimeter security model is no longer effective. How do you redefine the security strategy?', fr: 'Votre organisation migre des charges de travail critiques vers une architecture multi-cloud (AWS + Azure) avec des microservices Kubernetes. Le modèle de sécurité périmétrique traditionnel n\'est plus efficace. Comment redéfinissez-vous la stratégie de sécurité ?' }, options: [{ id: 'a', text: { es: 'Adoptar Cloud-Native Security con CSPM/CWPP, implementar service mesh con mTLS, políticas de seguridad como código (OPA), RBAC granular, cifrado end-to-end, monitoreo unificado con SIEM cloud-native y entrenamiento del equipo en seguridad cloud', en: 'Adopt Cloud-Native Security with CSPM/CWPP, implement service mesh with mTLS, security policies as code (OPA), granular RBAC, end-to-end encryption, unified monitoring with cloud-native SIEM, and train the team in cloud security', fr: 'Adopter la Cloud-Native Security avec CSPM/CWPP, implémenter un service mesh avec mTLS, des politiques de sécurité en tant que code (OPA), RBAC granulaire, chiffrement end-to-end, surveillance unifiée avec SIEM cloud-native et former l\'équipe en sécurité cloud' }, value: 100 }, { id: 'b', text: { es: 'Extender el firewall perimetral actual a los entornos cloud con VPN site-to-site', en: 'Extend the current perimeter firewall to cloud environments with site-to-site VPN', fr: 'Étendre le pare-feu périmétrique actuel aux environnements cloud avec VPN site-to-site' }, value: 20 }, { id: 'c', text: { es: 'Delegar la seguridad completamente a los proveedores cloud (shared responsibility)', en: 'Delegate security completely to cloud providers (shared responsibility)', fr: 'Déléguer la sécurité complètement aux fournisseurs cloud (responsabilité partagée)' }, value: 10 }, { id: 'd', text: { es: 'Mantener las cargas de trabajo más sensibles on-premise y migrar solo las menos críticas', en: 'Keep the most sensitive workloads on-premise and migrate only the less critical ones', fr: 'Garder les charges de travail les plus sensibles on-premise et migrer seulement les moins critiques' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-cyber-rd-3', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'ai-powered-threats', type: 'scale', content: { es: '¿Qué tan preparado está para defender a su organización contra amenazas que utilizan inteligencia artificial (deepfakes, phishing generado por IA, malware adaptativo)?', en: 'How prepared are you to defend your organization against threats that use artificial intelligence (deepfakes, AI-generated phishing, adaptive malware)?', fr: 'Dans quelle mesure êtes-vous prêt à défendre votre organisation contre les menaces utilisant l\'intelligence artificielle (deepfakes, phishing généré par IA, malware adaptatif) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco estas amenazas teóricamente pero no he implementado defensas específicas', en: 'I know these threats theoretically but have not implemented specific defenses', fr: 'Je connais ces menaces théoriquement mais je n\'ai pas implémenté de défenses spécifiques' }, max: { es: 'He implementado defensas anti-IA y participo activamente en investigación de amenazas IA', en: 'I have implemented anti-AI defenses and actively participate in AI threat research', fr: 'J\'ai implémenté des défenses anti-IA et je participe activement à la recherche sur les menaces IA' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-cyber-rd-4', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'regulatory-evolution', type: 'scale', content: { es: '¿Qué tan actualizado está sobre las regulaciones emergentes de ciberseguridad y privacidad (NIS2, DORA, AI Act, leyes de protección de datos de LATAM)?', en: 'How up-to-date are you on emerging cybersecurity and privacy regulations (NIS2, DORA, AI Act, LATAM data protection laws)?', fr: 'Dans quelle mesure êtes-vous à jour sur les réglementations émergentes de cybersécurité et de confidentialité (NIS2, DORA, AI Act, lois de protection des données d\'Amérique latine) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco las regulaciones principales pero no sigo activamente las nuevas', en: 'I know the main regulations but do not actively follow new ones', fr: 'Je connais les principales réglementations mais je ne suis pas activement les nouvelles' }, max: { es: 'Sigo activamente todas las regulaciones emergentes y he adaptado programas de cumplimiento proactivamente', en: 'I actively follow all emerging regulations and have proactively adapted compliance programs', fr: 'Je suis activement toutes les réglementations émergentes et j\'ai adapté proactivement les programmes de conformité' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-cyber-rd-5', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'cloud-security-evolution', type: 'scenario', content: { es: 'Su organización ha sufrido un incidente de seguridad: un desarrollador publicó accidentalmente claves de API y credenciales de base de datos de producción en un repositorio público de GitHub. Las credenciales estuvieron expuestas durante 48 horas antes de ser detectadas por un servicio de monitoreo externo.\nContexto: Las credenciales dan acceso al entorno de producción cloud (AWS) con datos de 200,000 clientes. No hay certeza de si alguien las utilizó. La empresa debe cumplir con GDPR.', en: 'Your organization has suffered a security incident: a developer accidentally published API keys and production database credentials to a public GitHub repository. The credentials were exposed for 48 hours before being detected by an external monitoring service.\nContext: The credentials provide access to the cloud production environment (AWS) with data from 200,000 customers. There is no certainty whether anyone used them. The company must comply with GDPR.', fr: 'Votre organisation a subi un incident de sécurité : un développeur a accidentellement publié des clés API et des identifiants de base de données de production dans un dépôt GitHub public. Les identifiants ont été exposés pendant 48 heures avant d\'être détectés.\nContexte : Les identifiants donnent accès à l\'environnement de production cloud (AWS) avec des données de 200 000 clients. Il n\'y a pas de certitude que quelqu\'un les ait utilisés. L\'entreprise doit se conformer au RGPD.' }, rubric: { es: 'Evaluar: (1) Contención inmediata (rotación de credenciales, revocación), (2) Análisis forense de accesos con las credenciales comprometidas, (3) Evaluación de impacto en datos personales (DPIA), (4) Notificación a la autoridad de protección de datos (72h GDPR), (5) Medidas preventivas (secret scanning, vault, políticas), (6) Comunicación con clientes afectados si corresponde.', en: 'Evaluate: (1) Immediate containment (credential rotation, revocation), (2) Forensic analysis of accesses with compromised credentials, (3) Personal data impact assessment (DPIA), (4) Data protection authority notification (72h GDPR), (5) Preventive measures (secret scanning, vault, policies), (6) Communication with affected customers if applicable.', fr: 'Évaluer : (1) Confinement immédiat (rotation des identifiants, révocation), (2) Analyse forensique des accès avec les identifiants compromis, (3) Évaluation d\'impact sur les données personnelles (DPIA), (4) Notification à l\'autorité de protection des données (72h RGPD), (5) Mesures préventives (secret scanning, vault, politiques), (6) Communication avec les clients affectés le cas échéant.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-cyber-rd-6', profileId: 'cybersecurity-analyst', categoryId: 'tech-cyber-readiness', competencyId: 'regulatory-evolution', type: 'open-text', content: { es: 'Describa cómo prepararía a una organización para cumplir con múltiples regulaciones de ciberseguridad y privacidad simultáneamente (ej. GDPR + ley local de protección de datos + estándar sectorial). ¿Cómo evitaría la duplicación de esfuerzos y controles?', en: 'Describe how you would prepare an organization to comply with multiple cybersecurity and privacy regulations simultaneously (e.g., GDPR + local data protection law + industry standard). How would you avoid duplication of efforts and controls?', fr: 'Décrivez comment vous prépareriez une organisation à se conformer simultanément à plusieurs réglementations de cybersécurité et de confidentialité (ex. RGPD + loi locale de protection des données + norme sectorielle). Comment éviteriez-vous la duplication des efforts et des contrôles ?' }, rubric: { es: 'Evaluar: (1) Mapeo de requisitos comunes entre regulaciones, (2) Framework unificado de controles, (3) Automatización de evidencia de cumplimiento, (4) Roles y responsabilidades claras (DPO, CISO), (5) Proceso de monitoreo continuo de cambios regulatorios, (6) Colaboración con legal y compliance.', en: 'Evaluate: (1) Mapping of common requirements across regulations, (2) Unified controls framework, (3) Compliance evidence automation, (4) Clear roles and responsibilities (DPO, CISO), (5) Continuous regulatory change monitoring process, (6) Collaboration with legal and compliance.', fr: 'Évaluer : (1) Cartographie des exigences communes entre réglementations, (2) Cadre unifié de contrôles, (3) Automatisation des preuves de conformité, (4) Rôles et responsabilités clairs (DPO, CISO), (5) Processus de surveillance continue des changements réglementaires, (6) Collaboration avec le juridique et la conformité.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

// ============================================================================
