export const techApmProfessionalQuestions: Question[] = [
  { id: 'tech-apm-prof-1', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'agile-frameworks', type: 'multiple-choice', content: { es: 'Lidera un equipo de 40 personas dividido en 5 squads que desarrollan una plataforma compleja. Los squads tienen dependencias cruzadas frecuentes que causan bloqueos y retrasos. Actualmente usan Scrum a nivel de squad pero no hay coordinación formal entre ellos. ¿Qué enfoque implementa?', en: 'You lead a team of 40 people divided into 5 squads developing a complex platform. Squads have frequent cross-dependencies causing blocks and delays. They currently use Scrum at squad level but there is no formal coordination between them. What approach do you implement?', fr: 'Vous dirigez une équipe de 40 personnes divisée en 5 squads développant une plateforme complexe. Les squads ont des dépendances croisées fréquentes causant des blocages et retards. Ils utilisent Scrum au niveau squad mais il n\'y a pas de coordination formelle entre eux. Quelle approche implémentez-vous ?' }, options: [{ id: 'a', text: { es: 'Implementar SAFe Essential o LeSS con PI Planning trimestral, Scrum of Scrums semanal, tablero de dependencias compartido, métricas de flujo cross-squad y roles de coordinación (Release Train Engineer)', en: 'Implement SAFe Essential or LeSS with quarterly PI Planning, weekly Scrum of Scrums, shared dependency board, cross-squad flow metrics, and coordination roles (Release Train Engineer)', fr: 'Implémenter SAFe Essential ou LeSS avec PI Planning trimestriel, Scrum of Scrums hebdomadaire, tableau de dépendances partagé, métriques de flux cross-squad et rôles de coordination (Release Train Engineer)' }, value: 100 }, { id: 'b', text: { es: 'Reorganizar los squads para eliminar las dependencias y que cada uno sea completamente autónomo', en: 'Reorganize squads to eliminate dependencies and make each one completely autonomous', fr: 'Réorganiser les squads pour éliminer les dépendances et rendre chacun complètement autonome' }, value: 45 }, { id: 'c', text: { es: 'Agregar un sprint de integración cada 3 sprints para resolver las dependencias', en: 'Add an integration sprint every 3 sprints to resolve dependencies', fr: 'Ajouter un sprint d\'intégration tous les 3 sprints pour résoudre les dépendances' }, value: 30 }, { id: 'd', text: { es: 'Crear un equipo de arquitectura que coordine todas las dependencias técnicas', en: 'Create an architecture team that coordinates all technical dependencies', fr: 'Créer une équipe d\'architecture qui coordonne toutes les dépendances techniques' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-apm-prof-2', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'delivery-management', type: 'multiple-choice', content: { es: 'A mitad de un proyecto crítico, el alcance ha crecido un 40% desde la planificación inicial, el equipo muestra signos de burnout, y el stakeholder principal presiona para mantener la fecha de entrega original. ¿Cómo maneja esta situación?', en: 'Halfway through a critical project, scope has grown 40% since initial planning, the team shows signs of burnout, and the main stakeholder pushes to maintain the original delivery date. How do you handle this situation?', fr: 'À mi-chemin d\'un projet critique, le périmètre a augmenté de 40% depuis la planification initiale, l\'équipe montre des signes de burnout et le principal stakeholder pousse pour maintenir la date de livraison originale. Comment gérez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Presentar datos: velocity real vs. planificada, burndown actualizado, análisis de riesgo. Negociar con el stakeholder: reducir alcance (MoSCoW), ajustar fecha o agregar recursos. Priorizar el bienestar del equipo con acciones concretas y establecer un proceso formal de control de cambios', en: 'Present data: actual vs. planned velocity, updated burndown, risk analysis. Negotiate with stakeholder: reduce scope (MoSCoW), adjust date, or add resources. Prioritize team wellbeing with concrete actions and establish a formal change control process', fr: 'Présenter les données : vélocité réelle vs. planifiée, burndown mis à jour, analyse de risque. Négocier avec le stakeholder : réduire le périmètre (MoSCoW), ajuster la date ou ajouter des ressources. Prioriser le bien-être de l\'équipe et établir un processus formel de contrôle des changements' }, value: 100 }, { id: 'b', text: { es: 'Aumentar las horas de trabajo del equipo para cumplir con la fecha original', en: 'Increase the team\'s working hours to meet the original date', fr: 'Augmenter les heures de travail de l\'équipe pour respecter la date originale' }, value: 10 }, { id: 'c', text: { es: 'Agregar más desarrolladores al equipo para acelerar la entrega', en: 'Add more developers to the team to speed up delivery', fr: 'Ajouter plus de développeurs à l\'équipe pour accélérer la livraison' }, value: 20 }, { id: 'd', text: { es: 'Escalar la situación a la dirección para que tomen la decisión', en: 'Escalate the situation to management for them to make the decision', fr: 'Escalader la situation à la direction pour qu\'ils prennent la décision' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-apm-prof-3', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'metrics-improvement', type: 'multiple-choice', content: { es: 'La velocity de su equipo ha sido inconsistente durante los últimos 6 sprints (variando entre 20 y 50 puntos), las retrospectivas se han vuelto repetitivas sin generar mejoras reales, y la satisfacción del equipo ha caído. ¿Cómo aborda esta situación?', en: 'Your team\'s velocity has been inconsistent over the last 6 sprints (ranging from 20 to 50 points), retrospectives have become repetitive without generating real improvements, and team satisfaction has dropped. How do you address this situation?', fr: 'La vélocité de votre équipe a été incohérente ces 6 derniers sprints (variant entre 20 et 50 points), les rétrospectives sont devenues répétitives sans générer d\'améliorations réelles et la satisfaction de l\'équipe a chuté. Comment abordez-vous cette situation ?' }, options: [{ id: 'a', text: { es: 'Analizar las métricas de flujo (cycle time, lead time, WIP) además de velocity, identificar cuellos de botella específicos, experimentar con formatos de retro diferentes (sailboat, 4Ls, starfish), establecer experiments con hipótesis medibles y celebrar las mejoras logradas', en: 'Analyze flow metrics (cycle time, lead time, WIP) in addition to velocity, identify specific bottlenecks, experiment with different retro formats (sailboat, 4Ls, starfish), establish experiments with measurable hypotheses, and celebrate achieved improvements', fr: 'Analyser les métriques de flux (cycle time, lead time, WIP) en plus de la vélocité, identifier les goulots d\'étranglement spécifiques, expérimenter avec différents formats de rétro, établir des expériences avec des hypothèses mesurables et célébrer les améliorations réalisées' }, value: 100 }, { id: 'b', text: { es: 'Reducir el tamaño de los sprints para tener resultados más consistentes', en: 'Reduce sprint size for more consistent results', fr: 'Réduire la taille des sprints pour des résultats plus consistants' }, value: 25 }, { id: 'c', text: { es: 'Establecer una velocity mínima obligatoria como meta del equipo', en: 'Establish a mandatory minimum velocity as a team goal', fr: 'Établir une vélocité minimum obligatoire comme objectif d\'équipe' }, value: 10 }, { id: 'd', text: { es: 'Reemplazar las retrospectivas con 1-on-1s para entender los problemas individuales', en: 'Replace retrospectives with 1-on-1s to understand individual problems', fr: 'Remplacer les rétrospectives par des 1-on-1 pour comprendre les problèmes individuels' }, value: 35 }], maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-apm-prof-4', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'backlog-prioritization', type: 'scale', content: { es: '¿Qué tan experimentado es usando técnicas de priorización como WSJF (Weighted Shortest Job First), RICE scoring, Cost of Delay y story mapping para gestionar backlogs complejos?', en: 'How experienced are you using prioritization techniques such as WSJF (Weighted Shortest Job First), RICE scoring, Cost of Delay, and story mapping to manage complex backlogs?', fr: 'Quelle est votre expérience avec les techniques de priorisation comme WSJF (Weighted Shortest Job First), RICE scoring, Cost of Delay et story mapping pour gérer des backlogs complexes ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Priorizo principalmente por urgencia o petición del stakeholder', en: 'I primarily prioritize by urgency or stakeholder request', fr: 'Je priorise principalement par urgence ou demande du stakeholder' }, max: { es: 'Uso sistemáticamente frameworks de priorización cuantitativos y facilito sesiones de priorización colaborativas', en: 'I systematically use quantitative prioritization frameworks and facilitate collaborative prioritization sessions', fr: 'J\'utilise systématiquement des frameworks de priorisation quantitatifs et je facilite des sessions de priorisation collaboratives' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-apm-prof-5', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'agile-frameworks', type: 'scenario', content: { es: 'Una empresa de logística le contrata para transformar su área de desarrollo de software (80 personas) de cascada a metodologías ágiles. Los equipos actuales están organizados por función (QA, desarrollo, diseño). Los gerentes de proyecto tradicionales sienten que perderán su rol. La dirección quiere ver resultados en 6 meses.\nContexto: La empresa tiene 5 proyectos activos, entregas semestrales con un 40% de retraso promedio, y alta rotación de personal (25% anual). No hay experiencia previa con agilidad.', en: 'A logistics company hires you to transform their software development area (80 people) from waterfall to agile methodologies. Current teams are organized by function (QA, development, design). Traditional project managers feel they will lose their role. Management wants to see results in 6 months.\nContext: The company has 5 active projects, semi-annual deliveries with 40% average delay, and high staff turnover (25% annual). There is no prior agile experience.', fr: 'Une entreprise de logistique vous embauche pour transformer son domaine de développement logiciel (80 personnes) de la cascade vers les méthodologies agiles. Les équipes actuelles sont organisées par fonction (QA, développement, design). Les chefs de projet traditionnels sentent qu\'ils perdront leur rôle. La direction veut voir des résultats en 6 mois.\nContexte : L\'entreprise a 5 projets actifs, des livraisons semestrielles avec 40% de retard moyen et une forte rotation du personnel (25% annuel). Pas d\'expérience agile antérieure.' }, rubric: { es: 'Evaluar: (1) Estrategia de transformación gradual (no big-bang), (2) Plan de transición de roles (PM tradicional a Scrum Master/PO), (3) Formación y coaching continuo, (4) Reorganización en equipos multifuncionales, (5) Métricas de transformación y quick wins, (6) Gestión de la resistencia al cambio y comunicación.', en: 'Evaluate: (1) Gradual transformation strategy (not big-bang), (2) Role transition plan (traditional PM to Scrum Master/PO), (3) Continuous training and coaching, (4) Reorganization into cross-functional teams, (5) Transformation metrics and quick wins, (6) Change resistance management and communication.', fr: 'Évaluer : (1) Stratégie de transformation graduelle, (2) Plan de transition des rôles, (3) Formation et coaching continus, (4) Réorganisation en équipes interfonctionnelles, (5) Métriques de transformation et quick wins, (6) Gestion de la résistance au changement et communication.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-apm-prof-6', profileId: 'agile-project-manager', categoryId: 'tech-apm-professional', competencyId: 'delivery-management', type: 'open-text', content: { es: 'Describa cómo gestionaría un proyecto con requisitos regulatorios estrictos (ej. software médico, financiero o aeronáutico) usando metodologías ágiles. ¿Cómo equilibraría la agilidad con la necesidad de documentación y trazabilidad regulatoria?', en: 'Describe how you would manage a project with strict regulatory requirements (e.g., medical, financial, or aeronautical software) using agile methodologies. How would you balance agility with the need for regulatory documentation and traceability?', fr: 'Décrivez comment vous géreriez un projet avec des exigences réglementaires strictes (ex. logiciel médical, financier ou aéronautique) en utilisant des méthodologies agiles. Comment équilibreriez-vous l\'agilité avec le besoin de documentation et de traçabilité réglementaire ?' }, rubric: { es: 'Evaluar: (1) Integración de requisitos regulatorios en la Definition of Done, (2) Automatización de documentación y trazabilidad, (3) Validación continua vs. validación big-bang, (4) Gestión de riesgos integrada en sprints, (5) Colaboración con el equipo regulatorio, (6) Ejemplos de frameworks (ej. Agile-GAMP5, DO-178C con Scrum).', en: 'Evaluate: (1) Integration of regulatory requirements into the Definition of Done, (2) Documentation and traceability automation, (3) Continuous validation vs. big-bang validation, (4) Risk management integrated into sprints, (5) Collaboration with regulatory team, (6) Framework examples (e.g., Agile-GAMP5, DO-178C with Scrum).', fr: 'Évaluer : (1) Intégration des exigences réglementaires dans la Definition of Done, (2) Automatisation de la documentation et de la traçabilité, (3) Validation continue vs. big-bang, (4) Gestion des risques intégrée dans les sprints, (5) Collaboration avec l\'équipe réglementaire, (6) Exemples de frameworks.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techApmSoftSkillsQuestions: Question[] = [
  { id: 'tech-apm-ss-1', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'facilitation-coaching', type: 'multiple-choice', content: { es: 'Durante un sprint planning, dos desarrolladores senior tienen un fuerte desacuerdo sobre la arquitectura técnica de una funcionalidad. La discusión se vuelve personal y el resto del equipo se desconecta. ¿Cómo facilita la situación?', en: 'During a sprint planning, two senior developers have a strong disagreement about the technical architecture of a feature. The discussion becomes personal and the rest of the team disengages. How do you facilitate the situation?', fr: 'Lors d\'un sprint planning, deux développeurs seniors ont un fort désaccord sur l\'architecture technique d\'une fonctionnalité. La discussion devient personnelle et le reste de l\'équipe se désengage. Comment facilitez-vous la situation ?' }, options: [{ id: 'a', text: { es: 'Pausar la discusión, redirigir al objetivo del planning, proponer un timebox de 15 min para que cada uno presente su propuesta con criterios objetivos (rendimiento, mantenibilidad, costo), facilitar una votación del equipo y agendar un spike si persiste la incertidumbre', en: 'Pause the discussion, redirect to the planning objective, propose a 15-min timebox for each to present their proposal with objective criteria (performance, maintainability, cost), facilitate a team vote, and schedule a spike if uncertainty persists', fr: 'Pauser la discussion, rediriger vers l\'objectif du planning, proposer un timebox de 15 min pour que chacun présente sa proposition avec des critères objectifs, faciliter un vote de l\'équipe et planifier un spike si l\'incertitude persiste' }, value: 100 }, { id: 'b', text: { es: 'Dejar que los seniors resuelvan el debate técnico entre ellos fuera de la reunión', en: 'Let the seniors resolve the technical debate between themselves outside the meeting', fr: 'Laisser les seniors résoudre le débat technique entre eux en dehors de la réunion' }, value: 40 }, { id: 'c', text: { es: 'Tomar la decisión usted mismo para avanzar con el planning', en: 'Make the decision yourself to move forward with planning', fr: 'Prendre la décision vous-même pour avancer avec le planning' }, value: 15 }, { id: 'd', text: { es: 'Escalar la decisión técnica al CTO o arquitecto principal', en: 'Escalate the technical decision to the CTO or lead architect', fr: 'Escalader la décision technique au CTO ou à l\'architecte principal' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-apm-ss-2', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'conflict-resolution', type: 'multiple-choice', content: { es: 'El Product Owner quiere entregar todas las funcionalidades planificadas sin reducir alcance, pero el equipo técnico insiste en dedicar el 30% del sprint a pagar deuda técnica que está afectando la velocidad de desarrollo. Ambos lados se niegan a ceder. ¿Cómo media?', en: 'The Product Owner wants to deliver all planned features without reducing scope, but the technical team insists on dedicating 30% of the sprint to pay technical debt that is affecting development speed. Neither side will budge. How do you mediate?', fr: 'Le Product Owner veut livrer toutes les fonctionnalités planifiées sans réduire le périmètre, mais l\'équipe technique insiste pour consacrer 30% du sprint à rembourser la dette technique qui affecte la vitesse de développement. Aucun côté ne veut céder. Comment médiez-vous ?' }, options: [{ id: 'a', text: { es: 'Facilitar un análisis basado en datos: mostrar la tendencia de velocity, cuantificar el costo de la deuda técnica en bugs y retrabajo, proponer una política sostenible (ej. 15-20% por sprint para deuda), y alinear ambas perspectivas con el objetivo común de entrega sostenible', en: 'Facilitate a data-driven analysis: show velocity trend, quantify technical debt cost in bugs and rework, propose a sustainable policy (e.g., 15-20% per sprint for debt), and align both perspectives with the common goal of sustainable delivery', fr: 'Faciliter une analyse basée sur les données : montrer la tendance de vélocité, quantifier le coût de la dette technique en bugs et retravail, proposer une politique durable (ex. 15-20% par sprint pour la dette) et aligner les deux perspectives vers l\'objectif commun de livraison durable' }, value: 100 }, { id: 'b', text: { es: 'Apoyar al equipo técnico ya que son los expertos en lo que necesita el código', en: 'Support the technical team since they are the experts on what the code needs', fr: 'Soutenir l\'équipe technique car ils sont les experts de ce dont le code a besoin' }, value: 35 }, { id: 'c', text: { es: 'Apoyar al Product Owner porque el negocio necesita funcionalidades entregadas', en: 'Support the Product Owner because the business needs delivered features', fr: 'Soutenir le Product Owner parce que le business a besoin de fonctionnalités livrées' }, value: 25 }, { id: 'd', text: { es: 'Alternar sprints: uno de funcionalidades y uno de deuda técnica', en: 'Alternate sprints: one for features and one for technical debt', fr: 'Alterner les sprints : un pour les fonctionnalités et un pour la dette technique' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-apm-ss-3', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'facilitation-coaching', type: 'scale', content: { es: '¿Qué tan efectivo es facilitando que los equipos se auto-organicen y tomen decisiones autónomas sin su intervención directa?', en: 'How effective are you at facilitating teams to self-organize and make autonomous decisions without your direct intervention?', fr: 'Quelle est votre efficacité à faciliter l\'auto-organisation des équipes et la prise de décisions autonomes sans votre intervention directe ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Tiendo a tomar las decisiones o indicar el camino a seguir', en: 'I tend to make decisions or indicate the path to follow', fr: 'J\'ai tendance à prendre les décisions ou à indiquer le chemin à suivre' }, max: { es: 'Los equipos que facilito se auto-organizan efectivamente y yo intervengo mínimamente', en: 'Teams I facilitate self-organize effectively and I intervene minimally', fr: 'Les équipes que je facilite s\'auto-organisent efficacement et j\'interviens minimalement' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-apm-ss-4', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'stakeholder-engagement', type: 'scale', content: { es: '¿Qué tan experimentado es gestionando las expectativas de múltiples stakeholders con prioridades conflictivas en un entorno ágil?', en: 'How experienced are you at managing expectations of multiple stakeholders with conflicting priorities in an agile environment?', fr: 'Quelle est votre expérience dans la gestion des attentes de multiples parties prenantes avec des priorités conflictuelles dans un environnement agile ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'He gestionado stakeholders en proyectos simples con pocas partes interesadas', en: 'I have managed stakeholders in simple projects with few interested parties', fr: 'J\'ai géré des parties prenantes dans des projets simples avec peu de parties intéressées' }, max: { es: 'He gestionado entornos con 10+ stakeholders con intereses divergentes y logrado alineamiento', en: 'I have managed environments with 10+ stakeholders with divergent interests and achieved alignment', fr: 'J\'ai géré des environnements avec 10+ parties prenantes avec des intérêts divergents et obtenu l\'alignement' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-apm-ss-5', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'conflict-resolution', type: 'ranking', content: { es: 'Ordene las siguientes habilidades según su importancia para un Scrum Master al resolver conflictos en el equipo:', en: 'Rank the following skills by importance for a Scrum Master when resolving team conflicts:', fr: 'Classez les compétences suivantes par importance pour un Scrum Master lors de la résolution de conflits dans l\'équipe :' }, options: [{ id: 'a', text: { es: 'Escucha activa y empatía con todas las partes', en: 'Active listening and empathy with all parties', fr: 'Écoute active et empathie avec toutes les parties' }, value: 1 }, { id: 'b', text: { es: 'Facilitar que el equipo encuentre su propia solución', en: 'Facilitate the team finding their own solution', fr: 'Faciliter que l\'équipe trouve sa propre solution' }, value: 2 }, { id: 'c', text: { es: 'Presentar datos objetivos que reenfoquen la discusión', en: 'Present objective data that refocuses the discussion', fr: 'Présenter des données objectives qui recentrent la discussion' }, value: 3 }, { id: 'd', text: { es: 'Autoridad para tomar la decisión final si el equipo no llega a acuerdo', en: 'Authority to make the final decision if the team cannot reach agreement', fr: 'Autorité pour prendre la décision finale si l\'équipe ne parvient pas à un accord' }, value: 4 }], maxScore: 100, aiEvaluated: false, order: 5, isActive: true },
  { id: 'tech-apm-ss-6', profileId: 'agile-project-manager', categoryId: 'tech-apm-soft-skills', competencyId: 'stakeholder-engagement', type: 'open-text', content: { es: 'Describa su enfoque para gestionar un stakeholder que constantemente cambia los requisitos, interrumpe los sprints con urgencias y no respeta los acuerdos de priorización. ¿Cómo protegería al equipo sin dañar la relación con este stakeholder?', en: 'Describe your approach to managing a stakeholder who constantly changes requirements, interrupts sprints with urgencies, and does not respect prioritization agreements. How would you protect the team without damaging the relationship with this stakeholder?', fr: 'Décrivez votre approche pour gérer un stakeholder qui change constamment les exigences, interrompt les sprints avec des urgences et ne respecte pas les accords de priorisation. Comment protégeriez-vous l\'équipe sans endommager la relation avec ce stakeholder ?' }, rubric: { es: 'Evaluar: (1) Establecimiento de working agreements claros, (2) Educación sobre el proceso ágil, (3) Transparencia con datos de impacto de las interrupciones, (4) Canalización de cambios a través del PO, (5) Balance entre protección del equipo y servicio al stakeholder, (6) Escalamiento constructivo si es necesario.', en: 'Evaluate: (1) Establishment of clear working agreements, (2) Education about the agile process, (3) Transparency with data on interruption impact, (4) Channeling changes through the PO, (5) Balance between team protection and stakeholder service, (6) Constructive escalation if needed.', fr: 'Évaluer : (1) Établissement d\'accords de travail clairs, (2) Éducation sur le processus agile, (3) Transparence avec les données d\'impact des interruptions, (4) Canalisation des changements via le PO, (5) Équilibre entre protection de l\'équipe et service au stakeholder, (6) Escalade constructive si nécessaire.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];

export const techApmReadinessQuestions: Question[] = [
  { id: 'tech-apm-rd-1', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'remote-hybrid-teams', type: 'multiple-choice', content: { es: 'Su equipo de 12 personas está distribuido en 4 zonas horarias (América, Europa, Asia). Las ceremonias Scrum se han vuelto ineficientes: no hay horario que funcione para todos, el daily se siente forzado y la comunicación asíncrona genera malentendidos. ¿Cómo reestructura el trabajo del equipo?', en: 'Your 12-person team is distributed across 4 time zones (Americas, Europe, Asia). Scrum ceremonies have become inefficient: no schedule works for everyone, the daily feels forced, and asynchronous communication creates misunderstandings. How do you restructure the team\'s work?', fr: 'Votre équipe de 12 personnes est distribuée sur 4 fuseaux horaires (Amériques, Europe, Asie). Les cérémonies Scrum sont devenues inefficaces : aucun horaire ne convient à tous, le daily semble forcé et la communication asynchrone crée des malentendus. Comment restructurez-vous le travail de l\'équipe ?' }, options: [{ id: 'a', text: { es: 'Adoptar un modelo async-first: dailys asíncronos con video updates, crear overlap hours para las reuniones que requieren interacción, usar documentación escrita como fuente de verdad, rotar horarios de ceremonias sincrónicas y establecer normas claras de comunicación asíncrona', en: 'Adopt an async-first model: asynchronous dailies with video updates, create overlap hours for meetings requiring interaction, use written documentation as source of truth, rotate synchronous ceremony schedules, and establish clear async communication norms', fr: 'Adopter un modèle async-first : dailys asynchrones avec mises à jour vidéo, créer des heures de chevauchement pour les réunions nécessitant une interaction, utiliser la documentation écrite comme source de vérité, faire tourner les horaires des cérémonies synchrones et établir des normes claires de communication asynchrone' }, value: 100 }, { id: 'b', text: { es: 'Pedir que todos se conecten en un horario central (ej. 9-13 UTC) para las ceremonias', en: 'Ask everyone to connect during a central schedule (e.g., 9-13 UTC) for ceremonies', fr: 'Demander à tous de se connecter pendant un horaire central (ex. 9-13 UTC) pour les cérémonies' }, value: 30 }, { id: 'c', text: { es: 'Eliminar las ceremonias Scrum formales y usar solo Kanban con comunicación asíncrona', en: 'Eliminate formal Scrum ceremonies and use only Kanban with async communication', fr: 'Éliminer les cérémonies Scrum formelles et utiliser uniquement Kanban avec communication asynchrone' }, value: 45 }, { id: 'd', text: { es: 'Dividir el equipo en sub-equipos por zona horaria que trabajen de forma independiente', en: 'Split the team into sub-teams by time zone that work independently', fr: 'Diviser l\'équipe en sous-équipes par fuseau horaire qui travaillent de manière indépendante' }, value: 40 }], maxScore: 100, aiEvaluated: false, order: 1, isActive: true },
  { id: 'tech-apm-rd-2', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'ai-augmented-pm', type: 'multiple-choice', content: { es: 'Nuevas herramientas de IA prometen automatizar la estimación de historias de usuario, detección de riesgos en el backlog, generación automática de reportes de progreso y sugerencias de asignación de tareas basadas en skills del equipo. ¿Cómo evalúa y adopta estas herramientas?', en: 'New AI tools promise to automate user story estimation, backlog risk detection, automatic progress report generation, and task assignment suggestions based on team skills. How do you evaluate and adopt these tools?', fr: 'De nouveaux outils d\'IA promettent d\'automatiser l\'estimation des user stories, la détection de risques dans le backlog, la génération automatique de rapports de progrès et les suggestions d\'affectation de tâches basées sur les compétences de l\'équipe. Comment évaluez-vous et adoptez-vous ces outils ?' }, options: [{ id: 'a', text: { es: 'Evaluar críticamente cada herramienta: probar con datos reales del equipo, comparar las estimaciones de IA vs. humanas durante 3-4 sprints, usar la IA como asistente (no reemplazo) del juicio del equipo, y medir el impacto en productividad y satisfacción del equipo', en: 'Critically evaluate each tool: test with real team data, compare AI vs. human estimates over 3-4 sprints, use AI as an assistant (not replacement) for team judgment, and measure impact on productivity and team satisfaction', fr: 'Évaluer critiquement chaque outil : tester avec les données réelles de l\'équipe, comparer les estimations IA vs. humaines sur 3-4 sprints, utiliser l\'IA comme assistant (pas remplacement) du jugement de l\'équipe et mesurer l\'impact sur la productivité et la satisfaction de l\'équipe' }, value: 100 }, { id: 'b', text: { es: 'Adoptar todas las herramientas disponibles para maximizar la automatización', en: 'Adopt all available tools to maximize automation', fr: 'Adopter tous les outils disponibles pour maximiser l\'automatisation' }, value: 20 }, { id: 'c', text: { es: 'No adoptar herramientas de IA porque la estimación y planificación deben ser humanas', en: 'Do not adopt AI tools because estimation and planning should be human', fr: 'Ne pas adopter d\'outils d\'IA car l\'estimation et la planification doivent être humaines' }, value: 25 }, { id: 'd', text: { es: 'Esperar a que otras empresas las prueben y compartir sus resultados', en: 'Wait for other companies to test them and share their results', fr: 'Attendre que d\'autres entreprises les testent et partagent leurs résultats' }, value: 30 }], maxScore: 100, aiEvaluated: false, order: 2, isActive: true },
  { id: 'tech-apm-rd-3', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'remote-hybrid-teams', type: 'scale', content: { es: '¿Qué tan efectivo es liderando equipos completamente remotos usando herramientas de colaboración asíncrona (Notion, Miro, Loom, Slack)?', en: 'How effective are you at leading fully remote teams using asynchronous collaboration tools (Notion, Miro, Loom, Slack)?', fr: 'Quelle est votre efficacité à diriger des équipes entièrement distantes en utilisant des outils de collaboration asynchrone (Notion, Miro, Loom, Slack) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Prefiero trabajo presencial y me cuesta coordinar equipos remotos', en: 'I prefer in-person work and struggle coordinating remote teams', fr: 'Je préfère le travail en présentiel et j\'ai du mal à coordonner des équipes distantes' }, max: { es: 'He liderado exitosamente equipos 100% remotos multinacionales durante años', en: 'I have successfully led multinational 100% remote teams for years', fr: 'J\'ai dirigé avec succès des équipes 100% distantes multinationales pendant des années' } }, maxScore: 100, aiEvaluated: false, order: 3, isActive: true },
  { id: 'tech-apm-rd-4', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'continuous-delivery-culture', type: 'scale', content: { es: '¿Qué tan familiarizado está con prácticas de entrega continua como trunk-based development, feature flags, testing in production y despliegues progresivos (canary/blue-green)?', en: 'How familiar are you with continuous delivery practices such as trunk-based development, feature flags, testing in production, and progressive deployments (canary/blue-green)?', fr: 'Dans quelle mesure êtes-vous familier avec les pratiques de livraison continue comme le trunk-based development, feature flags, testing en production et déploiements progressifs (canary/blue-green) ?' }, scaleMin: 1, scaleMax: 5, scaleLabels: { min: { es: 'Conozco los conceptos pero los equipos que gestiono hacen releases periódicas', en: 'I know the concepts but teams I manage do periodic releases', fr: 'Je connais les concepts mais les équipes que je gère font des releases périodiques' }, max: { es: 'He implementado pipelines de entrega continua con múltiples deploys diarios a producción', en: 'I have implemented continuous delivery pipelines with multiple daily production deploys', fr: 'J\'ai implémenté des pipelines de livraison continue avec plusieurs déploiements quotidiens en production' } }, maxScore: 100, aiEvaluated: false, order: 4, isActive: true },
  { id: 'tech-apm-rd-5', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'ai-augmented-pm', type: 'scenario', content: { es: 'La dirección quiere reducir los tiempos de entrega de proyectos un 30% usando IA. Le piden liderar un piloto de 3 meses con un equipo de 8 personas para integrar herramientas de IA en el proceso de gestión de proyectos ágil.\nContexto: El equipo nunca ha usado herramientas de IA. El presupuesto para herramientas es USD 5K mensuales. Los stakeholders esperan un reporte mensual de progreso con métricas claras. Hay escepticismo en el equipo sobre si la IA realmente ayudará.', en: 'Management wants to reduce project delivery times by 30% using AI. They ask you to lead a 3-month pilot with an 8-person team to integrate AI tools into the agile project management process.\nContext: The team has never used AI tools. The tool budget is USD 5K monthly. Stakeholders expect a monthly progress report with clear metrics. There is skepticism in the team about whether AI will really help.', fr: 'La direction veut réduire les temps de livraison de projets de 30% en utilisant l\'IA. On vous demande de diriger un pilote de 3 mois avec une équipe de 8 personnes pour intégrer des outils d\'IA dans le processus de gestion de projet agile.\nContexte : L\'équipe n\'a jamais utilisé d\'outils d\'IA. Le budget outils est de 5K USD mensuels. Les stakeholders attendent un rapport mensuel avec des métriques claires. Il y a du scepticisme dans l\'équipe.' }, rubric: { es: 'Evaluar: (1) Selección de herramientas de IA apropiadas al contexto, (2) Plan de adoption gradual y capacitación, (3) Definición de métricas baseline y objetivo, (4) Gestión del escepticismo del equipo, (5) Framework de evaluación de resultados, (6) Recomendaciones para escalamiento post-piloto.', en: 'Evaluate: (1) Selection of AI tools appropriate to context, (2) Gradual adoption and training plan, (3) Baseline and target metrics definition, (4) Management of team skepticism, (5) Results evaluation framework, (6) Recommendations for post-pilot scaling.', fr: 'Évaluer : (1) Sélection d\'outils IA appropriés au contexte, (2) Plan d\'adoption graduelle et formation, (3) Définition des métriques baseline et cible, (4) Gestion du scepticisme de l\'équipe, (5) Cadre d\'évaluation des résultats, (6) Recommandations pour le passage à l\'échelle post-pilote.' }, maxScore: 100, aiEvaluated: true, order: 5, isActive: true },
  { id: 'tech-apm-rd-6', profileId: 'agile-project-manager', categoryId: 'tech-apm-readiness', competencyId: 'continuous-delivery-culture', type: 'open-text', content: { es: 'Describa cómo transformaría un equipo que actualmente hace releases mensuales con procesos manuales de QA y deploy a un modelo de entrega continua con múltiples deploys diarios. ¿Cuáles son los prerequisitos técnicos y culturales necesarios?', en: 'Describe how you would transform a team that currently does monthly releases with manual QA and deploy processes to a continuous delivery model with multiple daily deploys. What are the necessary technical and cultural prerequisites?', fr: 'Décrivez comment vous transformeriez une équipe qui fait actuellement des releases mensuelles avec des processus manuels de QA et déploiement vers un modèle de livraison continue avec plusieurs déploiements quotidiens. Quels sont les prérequis techniques et culturels nécessaires ?' }, rubric: { es: 'Evaluar: (1) Pipeline de CI/CD automatizado, (2) Estrategia de testing automatizado (pirámide de tests), (3) Feature flags y despliegues progresivos, (4) Monitoreo y rollback automático, (5) Cambio cultural: ownership, blameless post-mortems, (6) Plan de transición gradual con métricas de éxito.', en: 'Evaluate: (1) Automated CI/CD pipeline, (2) Automated testing strategy (test pyramid), (3) Feature flags and progressive deployments, (4) Monitoring and automatic rollback, (5) Cultural change: ownership, blameless post-mortems, (6) Gradual transition plan with success metrics.', fr: 'Évaluer : (1) Pipeline CI/CD automatisé, (2) Stratégie de tests automatisés (pyramide de tests), (3) Feature flags et déploiements progressifs, (4) Surveillance et rollback automatique, (5) Changement culturel : ownership, post-mortems sans blame, (6) Plan de transition graduel avec métriques de succès.' }, maxScore: 100, aiEvaluated: true, order: 6, isActive: true },
];
